-- 013: AP Biology Part 1 — bulk questions for first 4 subtopics
-- Subtopics: cell-structure, genetics, evolution, ecology
-- Target: 50 easy / 50 medium / 50 hard per subtopic (adding ~48-49 new per difficulty per subtopic)

INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES

-- ============================================================
-- CELL STRUCTURE — EASY (48 questions)
-- ============================================================
('AP Biology','easy','cell-structure','What is the primary function of the nucleus in a eukaryotic cell?','Produce energy as ATP','Store and transmit genetic information','Synthesize lipids for the membrane','Break down waste materials','B','The nucleus houses the cell''s DNA and directs gene expression and cell reproduction, serving as the control center of the eukaryotic cell.'),
('AP Biology','easy','cell-structure','Which organelle is the site of protein synthesis?','Golgi apparatus','Lysosome','Ribosome','Vacuole','C','Ribosomes translate mRNA into polypeptide chains; they are found free in the cytoplasm or attached to the rough endoplasmic reticulum.'),
('AP Biology','easy','cell-structure','What type of cell lacks a membrane-bound nucleus?','Plant cell','Animal cell','Fungal cell','Bacterial cell','D','Bacteria are prokaryotes whose genetic material lies in a nucleoid region without a surrounding nuclear envelope.'),
('AP Biology','easy','cell-structure','Which structure is found in plant cells but NOT in animal cells?','Ribosome','Mitochondria','Cell wall','Plasma membrane','C','Plant cells have a rigid cell wall made of cellulose outside the plasma membrane; animal cells lack this structure.'),
('AP Biology','easy','cell-structure','What is the function of the Golgi apparatus?','Produce ATP through respiration','Package and ship proteins to their destinations','Carry out photosynthesis','Digest worn-out organelles','B','The Golgi apparatus modifies, sorts, and packages proteins and lipids into vesicles for secretion or delivery to other organelles.'),
('AP Biology','easy','cell-structure','Which organelle contains digestive enzymes used to break down cellular debris?','Peroxisome','Ribosome','Lysosome','Smooth ER','C','Lysosomes contain hydrolytic enzymes that break down macromolecules, old organelles, and foreign materials in a process called autophagy or phagocytosis.'),
('AP Biology','easy','cell-structure','What is the main component of the plasma membrane?','Cellulose','Phospholipid bilayer','Peptidoglycan','Glycogen','B','The plasma membrane is composed primarily of a phospholipid bilayer with embedded proteins that controls what enters and exits the cell.'),
('AP Biology','easy','cell-structure','Which type of transport moves substances against a concentration gradient and requires energy?','Osmosis','Facilitated diffusion','Simple diffusion','Active transport','D','Active transport uses ATP to move molecules from areas of lower concentration to higher concentration, against the electrochemical gradient.'),
('AP Biology','easy','cell-structure','What is the function of the smooth endoplasmic reticulum?','Synthesize ribosomes','Detoxify chemicals and synthesize lipids','Store genetic information','Package proteins for export','B','The smooth ER lacks ribosomes and is involved in lipid synthesis, detoxification of drugs and poisons, and calcium ion storage.'),
('AP Biology','easy','cell-structure','Which cellular structure provides structural support and helps with cell movement?','Nucleus','Cytoskeleton','Vacuole','Golgi apparatus','B','The cytoskeleton is a network of protein filaments (microtubules, microfilaments, intermediate filaments) that maintains cell shape and enables movement.'),
('AP Biology','easy','cell-structure','What molecule makes up the cell walls of fungi?','Cellulose','Peptidoglycan','Chitin','Lignin','C','Fungal cell walls are composed of chitin, a nitrogen-containing polysaccharide, which is distinct from the cellulose in plant cell walls.'),
('AP Biology','easy','cell-structure','In which part of the cell does the cytoplasm reside?','Inside the nucleus','Between the plasma membrane and nuclear envelope','Only in the organelles','Inside the mitochondria','B','The cytoplasm is the gel-like substance filling the space between the plasma membrane and the nuclear envelope, containing organelles and dissolved molecules.'),
('AP Biology','easy','cell-structure','What is the role of centrioles in animal cells?','Synthesize proteins','Organize the mitotic spindle during cell division','Store calcium ions','Produce ATP','B','Centrioles form the centrosome that organizes the spindle fibers (microtubules) that separate chromosomes during mitosis and meiosis.'),
('AP Biology','easy','cell-structure','Which organelle stores water, nutrients, or waste in plant cells?','Lysosome','Central vacuole','Peroxisome','Smooth ER','B','The large central vacuole in plant cells stores water (maintaining turgor pressure), nutrients, pigments, and waste products.'),
('AP Biology','easy','cell-structure','What process allows water to move across a semipermeable membrane from low solute to high solute concentration?','Active transport','Endocytosis','Osmosis','Exocytosis','C','Osmosis is the passive movement of water across a selectively permeable membrane from a region of lower solute concentration (higher water potential) to higher solute concentration.'),
('AP Biology','easy','cell-structure','Which type of endoplasmic reticulum has ribosomes attached to its surface?','Smooth ER','Rough ER','Sarcoplasmic reticulum','Transitional ER','B','Rough ER is studded with ribosomes that synthesize proteins destined for secretion or membrane insertion; the ribosomes give it a rough appearance under the electron microscope.'),
('AP Biology','easy','cell-structure','What is the outer boundary of a plant cell called?','Plasma membrane','Cell wall','Tonoplast','Middle lamella','B','The cell wall is the rigid outer layer of a plant cell composed mainly of cellulose fibrils that provides structural support and protection.'),
('AP Biology','easy','cell-structure','Which cellular process involves the cell engulfing large particles by wrapping the membrane around them?','Exocytosis','Pinocytosis','Phagocytosis','Osmosis','C','Phagocytosis (cell eating) is a type of endocytosis where the cell membrane engulfs large solid particles like bacteria or debris into a phagosome.'),
('AP Biology','easy','cell-structure','What connects adjacent plant cells and allows communication between them?','Tight junctions','Desmosomes','Plasmodesmata','Gap junctions','C','Plasmodesmata are channels through the cell walls of adjacent plant cells that allow water, small molecules, and signals to pass between cells.'),
('AP Biology','easy','cell-structure','Which organelle is responsible for modifying newly synthesized proteins with carbohydrate groups?','Mitochondria','Golgi apparatus','Lysosome','Nucleolus','B','The Golgi apparatus adds carbohydrate groups to proteins (glycosylation) and modifies lipids before packaging them into vesicles for transport.'),
('AP Biology','easy','cell-structure','What is the nucleolus responsible for producing?','Messenger RNA','Ribosomal RNA (rRNA)','Transfer RNA','DNA','B','The nucleolus is a dense region within the nucleus where ribosomal RNA is transcribed and ribosomal subunits are assembled before export to the cytoplasm.'),
('AP Biology','easy','cell-structure','Which molecule forms the fluid mosaic model of the plasma membrane alongside phospholipids?','Cellulose','Cholesterol and proteins','Glycogen','RNA','B','The fluid mosaic model describes the plasma membrane as a phospholipid bilayer embedded with proteins and cholesterol, which modulates membrane fluidity.'),
('AP Biology','easy','cell-structure','What is the term for the diffusion of molecules through a membrane via transport proteins without energy input?','Active transport','Bulk flow','Facilitated diffusion','Exocytosis','C','Facilitated diffusion uses channel or carrier proteins to move molecules down their concentration gradient without requiring ATP.'),
('AP Biology','easy','cell-structure','Which structure in the cell is responsible for producing subunits of ribosomes?','Nucleolus','Golgi body','Smooth ER','Peroxisome','A','The nucleolus synthesizes rRNA and assembles it with proteins to form ribosomal subunits that are then exported through nuclear pores to the cytoplasm.'),
('AP Biology','easy','cell-structure','What is the main function of peroxisomes?','Protein synthesis','Break down fatty acids and neutralize hydrogen peroxide','Package proteins for secretion','Perform photosynthesis','B','Peroxisomes contain oxidative enzymes that break down fatty acids and amino acids, producing hydrogen peroxide, which is then neutralized by catalase within the same organelle.'),
('AP Biology','easy','cell-structure','Which ion is primarily pumped out of cells by the sodium-potassium pump?','Calcium','Hydrogen','Sodium','Chloride','C','The Na+/K+ ATPase pump uses one ATP to move 3 Na+ ions out of the cell and 2 K+ ions in, maintaining the electrochemical gradient essential for nerve and muscle function.'),
('AP Biology','easy','cell-structure','What is the term for the network of protein fibers that gives cells their shape?','Cell wall','Cytoskeleton','Extracellular matrix','Nuclear lamina','B','The cytoskeleton consists of microtubules, actin microfilaments, and intermediate filaments that maintain cell shape and facilitate intracellular transport and movement.'),
('AP Biology','easy','cell-structure','In the endomembrane system, where are secretory proteins first synthesized?','Free ribosomes','Rough ER','Golgi apparatus','Plasma membrane','B','Secretory proteins are synthesized by ribosomes on the rough ER and co-translationally inserted into the ER lumen for further processing and transport.'),
('AP Biology','easy','cell-structure','Which organelle contains its own DNA and ribosomes, suggesting an endosymbiotic origin?','Golgi apparatus','Lysosome','Mitochondria','Peroxisome','C','Mitochondria have their own circular DNA, 70S ribosomes, and double membrane, which is strong evidence for their origin as engulfed free-living bacteria (endosymbiotic theory).'),
('AP Biology','easy','cell-structure','What is turgor pressure in plant cells?','Pressure exerted by the nucleus on organelles','Pressure of water against the cell wall, keeping the cell firm','Force generated by the cytoskeleton','Pressure inside the mitochondria','B','Turgor pressure is the outward force exerted by water inside the vacuole against the cell wall; it keeps plant cells firm and is essential for plant support.'),
('AP Biology','easy','cell-structure','Which process releases vesicle contents to the outside of the cell?','Endocytosis','Phagocytosis','Exocytosis','Pinocytosis','C','During exocytosis, vesicles fuse with the plasma membrane and release their contents extracellularly, used for secreting hormones, enzymes, and neurotransmitters.'),
('AP Biology','easy','cell-structure','What are tight junctions in animal cells used for?','Allow passage of molecules between cells','Seal neighboring cells to prevent leakage between them','Anchor cells to the extracellular matrix','Form electrical connections between cells','B','Tight junctions fuse adjacent animal cells together near their apical surfaces, preventing fluids from leaking between cells — essential in the gut and kidney tubules.'),
('AP Biology','easy','cell-structure','Which component of the cytoskeleton is involved in muscle contraction?','Intermediate filaments','Microtubules','Actin microfilaments','Nuclear lamins','C','Actin microfilaments interact with myosin motor proteins to generate the sliding forces responsible for muscle contraction and cell motility.'),
('AP Biology','easy','cell-structure','What is a selectively permeable membrane?','A membrane that allows all molecules to pass','A membrane that allows only water to pass','A membrane that controls which molecules can enter and exit','A membrane made entirely of proteins','C','A selectively permeable membrane allows certain molecules (like water and small nonpolar molecules) to pass freely while restricting others, maintaining the cell''s internal environment.'),
('AP Biology','easy','cell-structure','Which part of a phospholipid is hydrophilic?','The fatty acid tails','The phosphate head group','The glycerol backbone only','The entire molecule','B','The phosphate head of a phospholipid is polar and interacts with water (hydrophilic), while the fatty acid tails are nonpolar and repel water (hydrophobic).'),
('AP Biology','easy','cell-structure','What is the function of gap junctions in animal cells?','Prevent leakage between cells','Allow direct cytoplasmic communication between adjacent cells','Anchor cells to the extracellular matrix','Package proteins for secretion','B','Gap junctions are protein channels (connexins) that connect adjacent animal cells, allowing ions and small molecules to pass directly between cytoplasms for electrical and chemical coupling.'),
('AP Biology','easy','cell-structure','Which structure in the chloroplast is where the light reactions of photosynthesis occur?','Stroma','Thylakoid membrane','Outer membrane','Intermembrane space','B','The thylakoid membranes house the photosystems, electron transport chain, and ATP synthase used in the light-dependent reactions to produce ATP and NADPH.'),
('AP Biology','easy','cell-structure','What is the matrix of the mitochondria?','The outer membrane space','The inner fluid compartment where the Krebs cycle occurs','The membrane where ATP synthase is located','The space between inner and outer membranes','B','The mitochondrial matrix is the innermost compartment containing enzymes for the Krebs cycle, mitochondrial DNA, and ribosomes.'),
('AP Biology','easy','cell-structure','Which type of cell junction anchors cells to each other and to the extracellular matrix via intermediate filaments?','Tight junction','Gap junction','Desmosome','Plasmodesmata','C','Desmosomes are buttonlike junctions that use cadherins and intermediate filaments to anchor adjacent cells together, providing mechanical strength in tissues like skin and heart muscle.'),
('AP Biology','easy','cell-structure','What is the name of the aqueous fluid inside the chloroplast, surrounding the thylakoids?','Matrix','Cytosol','Stroma','Lumen','C','The stroma is the fluid-filled space of the chloroplast surrounding the thylakoids, where the Calvin cycle enzymes are located and carbon fixation occurs.'),
('AP Biology','easy','cell-structure','Which organelle is most abundant in cells that secrete large amounts of protein?','Smooth ER','Mitochondria','Rough ER','Peroxisome','C','Cells that secrete proteins (like pancreatic acinar cells) have extensive rough ER because secretory proteins are synthesized by ribosomes attached to the rough ER.'),
('AP Biology','easy','cell-structure','What is the role of cholesterol in the plasma membrane?','Act as a transport protein','Provide energy storage','Stabilize membrane fluidity at varying temperatures','Form the hydrophilic head groups','C','Cholesterol inserts between phospholipids, reducing fluidity at high temperatures and preventing solidification at low temperatures, buffering the membrane against temperature extremes.'),
('AP Biology','easy','cell-structure','Which cytoskeletal element forms the mitotic spindle during cell division?','Actin microfilaments','Intermediate filaments','Microtubules','Spectrin','C','Microtubules polymerize from the centrosomes to form the spindle apparatus that attaches to kinetochores and pulls chromosomes to opposite poles during mitosis.'),
('AP Biology','easy','cell-structure','What is the intermembrane space of the mitochondria?','The area inside the inner membrane','The space between the inner and outer mitochondrial membranes','The matrix surrounding the mitochondria','The space inside the thylakoid','B','The intermembrane space is the region between the inner and outer mitochondrial membranes where protons accumulate during the electron transport chain, creating the proton gradient used by ATP synthase.'),
('AP Biology','easy','cell-structure','In a plant cell, what structure regulates movement between the cytoplasm and the vacuole?','Plasma membrane','Tonoplast','Cell wall','Nuclear envelope','B','The tonoplast is the membrane surrounding the central vacuole in plant cells; it regulates the movement of ions and molecules between the cytoplasm and vacuole interior.'),
('AP Biology','easy','cell-structure','What type of protein spans the entire width of the plasma membrane?','Peripheral protein','Integral (transmembrane) protein','Glycoprotein only','Cytoskeletal anchor','B','Integral transmembrane proteins span the entire lipid bilayer and typically function as channels, carriers, receptors, or enzymes embedded in the membrane.'),
('AP Biology','easy','cell-structure','Which structure contains the genetic material of a prokaryotic cell?','Membrane-bound nucleus','Nucleoid region','Mitochondria','Endoplasmic reticulum','B','Prokaryotes lack a true nucleus; their circular DNA is found in the nucleoid region, a distinct but not membrane-enclosed area of the cytoplasm.'),
('AP Biology','easy','cell-structure','What is the function of the extracellular matrix (ECM) in animal cells?','Produce ATP for the cell','Provide structural support and mediate cell signaling','Store genetic information','Perform photosynthesis','B','The ECM is a network of proteins (collagen, fibronectin) and polysaccharides that supports cells, anchors them in place, and relays signals that regulate cell behavior.'),

-- ============================================================
-- CELL STRUCTURE — MEDIUM (49 questions)
-- ============================================================
('AP Biology','medium','cell-structure','A researcher treats cells with a drug that inhibits ATP synthase. Which of the following would be the most immediate consequence?','Ribosomes stop synthesizing proteins','The proton gradient across the inner mitochondrial membrane collapses','ATP production via oxidative phosphorylation is blocked','Glycolysis in the cytoplasm stops immediately','C','ATP synthase catalyzes the phosphorylation of ADP to ATP using the proton gradient; inhibiting it directly blocks oxidative phosphorylation while the proton gradient initially remains intact.'),
('AP Biology','medium','cell-structure','A cell secreting large amounts of a hormone would be expected to have an abundance of which organelles?','Large central vacuole and chloroplasts','Rough ER, Golgi apparatus, and secretory vesicles','Smooth ER and peroxisomes','Centrioles and lysosomes','B','Hormone secretion requires protein synthesis (rough ER), modification and packaging (Golgi), and transport to the membrane (secretory vesicles).'),
('AP Biology','medium','cell-structure','If a plant cell is placed in a hypotonic solution, what will happen?','The cell will shrink due to plasmolysis','The cell will swell but the cell wall prevents lysis','Water will leave the cell by osmosis','The cell will remain unchanged','B','In a hypotonic solution, water enters the cell by osmosis causing it to swell, but the rigid cell wall provides back-pressure (wall pressure), preventing the cell from bursting.'),
('AP Biology','medium','cell-structure','Which evidence best supports the endosymbiotic theory for the origin of mitochondria?','Mitochondria contain a single membrane','Mitochondria are found only in animal cells','Mitochondria have circular DNA and 70S ribosomes similar to bacteria','Mitochondria can be found free-living in the environment','C','Mitochondria share characteristics with bacteria: circular DNA, 70S ribosomes (not 80S like eukaryotic ribosomes), binary fission, and double membranes — consistent with an ancient endosymbiotic event.'),
('AP Biology','medium','cell-structure','A mutation that disrupts the signal sequence of a secretory protein would most likely result in which of the following?','The protein is degraded in the nucleus','The protein is synthesized but remains in the cytoplasm instead of entering the ER','The protein is sent to lysosomes','Transcription of the gene is prevented','B','The signal sequence targets the ribosome to the rough ER; without it, the protein is synthesized on free ribosomes and released into the cytosol instead of the secretory pathway.'),
('AP Biology','medium','cell-structure','How does the structure of the inner mitochondrial membrane increase ATP production efficiency?','It contains pores that allow free diffusion of protons','Its high folding (cristae) increases surface area for ATP synthase complexes','It is made of a single phospholipid layer to speed proton movement','It actively pumps ATP directly across the membrane','B','The cristae dramatically increase the inner membrane surface area, allowing more ATP synthase complexes to be embedded, thus increasing the rate of oxidative phosphorylation.'),
('AP Biology','medium','cell-structure','What would happen to a cell if all its lysosomes suddenly ruptured?','The cell would immediately divide','Digestive enzymes released into the cytoplasm would destroy cellular components','Protein synthesis would increase','The cell would undergo photosynthesis','B','Lysosomes contain hydrolytic enzymes active at low pH; if they rupture and release these enzymes into the neutral cytoplasm, they can digest proteins, lipids, and nucleic acids, causing cell death (autolysis).'),
('AP Biology','medium','cell-structure','A molecule of glucose is broken down in a cell. In which compartment does glycolysis occur?','Mitochondrial matrix','Inner mitochondrial membrane','Cytoplasm (cytosol)','Nucleus','C','Glycolysis takes place in the cytosol and does not require oxygen; it converts glucose into two pyruvate molecules, producing a net gain of 2 ATP and 2 NADH.'),
('AP Biology','medium','cell-structure','How do aquaporins increase the rate of osmosis across the plasma membrane?','They actively pump water against its gradient','They provide protein channels that facilitate rapid water movement','They break down the phospholipid bilayer','They increase the solute concentration gradient','B','Aquaporins are channel proteins that allow water to move rapidly through the membrane down its osmotic gradient, greatly increasing the rate of osmosis compared to diffusion through the lipid bilayer.'),
('AP Biology','medium','cell-structure','Which feature of the plasma membrane explains why nonpolar molecules diffuse across it more rapidly than polar molecules?','The membrane contains active transport pumps for nonpolar molecules','The hydrophobic interior of the bilayer is permeable to nonpolar molecules','Polar molecules are too large to cross any membrane','Nonpolar molecules use aquaporins to cross','B','The hydrophobic fatty acid tails in the interior of the bilayer allow nonpolar (lipid-soluble) molecules to dissolve through easily, while the same region repels polar and charged molecules.'),
('AP Biology','medium','cell-structure','A cell biologist observes that a protein synthesized in the rough ER is never delivered to the Golgi. Which of the following is the most likely cause?','The protein lacks a signal sequence','COPI vesicle formation is disrupted','The nuclear pore is blocked','Actin polymerization is inhibited','B','COPI vesicles mediate retrograde transport from the Golgi back to the ER, while COPII vesicles carry cargo from ER to Golgi; disrupting COPII vesicle budding would prevent ER-to-Golgi transport.'),
('AP Biology','medium','cell-structure','Why is the sodium-potassium pump considered electrogenic?','It pumps equal numbers of cations in both directions','It generates a net charge difference by moving 3 Na+ out for every 2 K+ in','It only functions in nerve cells','It uses light energy rather than ATP','B','The unequal exchange (3 Na+ out, 2 K+ in) means the pump moves more positive charges out than in, contributing to the negative resting membrane potential (electrogenic effect).'),
('AP Biology','medium','cell-structure','In which region of a chloroplast is carbon dioxide fixed into organic molecules?','Thylakoid lumen','Thylakoid membrane','Stroma','Outer membrane','C','The Calvin cycle occurs in the stroma, where RuBisCO incorporates CO2 into organic molecules using ATP and NADPH produced by the light reactions.'),
('AP Biology','medium','cell-structure','A cell treated with colchicine, which depolymerizes microtubules, would be UNABLE to perform which of the following?','Protein synthesis','Chromosomal separation during mitosis','Active transport of ions','Transcription of genes','B','Microtubules form the mitotic spindle that attaches to chromosomes at kinetochores and pulls them to opposite poles; without microtubules, chromosomes cannot segregate.'),
('AP Biology','medium','cell-structure','Which of the following best explains why red blood cells lyse in a hypotonic solution but plant cells do not?','Red blood cells lack a plasma membrane','Plant cells actively pump water out','Red blood cells have no cell wall to resist osmotic swelling','Plant cells have more aquaporins','C','Animal cells lack a cell wall; in a hypotonic solution, water enters until internal pressure bursts the membrane. Plant cell walls exert wall pressure that resists further swelling.'),
('AP Biology','medium','cell-structure','What is the significance of vesicle fusion to the correct destination membrane?','All vesicles fuse randomly with any membrane','SNARE proteins on vesicles and target membranes ensure specificity of fusion','ATP synthase directs vesicle targeting','Only lipid composition determines fusion','B','v-SNARE proteins on vesicles match complementary t-SNARE proteins on the correct target membrane, ensuring vesicles deliver their cargo to the right cellular compartment.'),
('AP Biology','medium','cell-structure','Which of the following accurately describes the fluid mosaic model?','The membrane is a rigid bilayer of proteins embedded in lipids','Lipids and proteins can move laterally within the bilayer','The membrane is a solid crystalline structure at body temperature','Proteins are permanently fixed in the lipid bilayer','B','The fluid mosaic model describes the membrane as a two-dimensional liquid; phospholipids and many proteins can move laterally, and the protein composition creates a mosaic pattern.'),
('AP Biology','medium','cell-structure','How does the endomembrane system coordinate protein secretion?','Proteins are synthesized in the Golgi and sent to the ER for modification','Proteins move from rough ER → Golgi → secretory vesicle → plasma membrane','Proteins are synthesized in the nucleus and exported directly','Mitochondria package proteins for secretion','B','The endomembrane system works as a pipeline: rough ER synthesizes and initially processes proteins, the Golgi modifies and sorts them, and secretory vesicles deliver them to the cell surface.'),
('AP Biology','medium','cell-structure','A drug inhibits clathrin-coated pit formation. Which process would be most directly affected?','Exocytosis of hormones','Receptor-mediated endocytosis','Osmosis across the membrane','Active ion transport','B','Receptor-mediated endocytosis depends on clathrin-coated pits that concentrate receptors and their ligands before pinching off as endocytic vesicles; inhibiting clathrin prevents this process.'),
('AP Biology','medium','cell-structure','Which of the following best explains why mitochondria are most abundant in muscle cells?','Muscle cells require large amounts of protein synthesis','Muscle cells have a high demand for ATP to power contraction','Mitochondria help muscle cells divide rapidly','Muscle cells need mitochondria for DNA replication','B','Muscle contraction requires continuous ATP hydrolysis by myosin; high metabolic demand means muscle cells contain many mitochondria to produce sufficient ATP by oxidative phosphorylation.'),
('AP Biology','medium','cell-structure','What determines which proteins are sorted to the lysosome rather than the plasma membrane?','The size of the protein','Mannose-6-phosphate tags added in the Golgi','The sequence of amino acids alone','The number of disulfide bonds','B','Proteins destined for lysosomes are tagged with mannose-6-phosphate in the Golgi, which is recognized by receptors that direct them into vesicles headed for late endosomes/lysosomes.'),
('AP Biology','medium','cell-structure','Why do cells use vesicles to transport materials through the endomembrane system rather than free diffusion?','Free diffusion would be faster','Vesicles maintain compartmentalization and allow directional, regulated transport','Diffusion cannot occur in aqueous environments','Vesicles generate the ATP needed for transport','B','Vesicular transport maintains the distinct chemical environments of each compartment and allows the cell to regulate the timing and destination of molecular cargo through specific targeting signals.'),
('AP Biology','medium','cell-structure','A researcher finds that blocking the proton gradient across the inner mitochondrial membrane stops ATP synthesis but does NOT stop electron transport. What does this suggest?','ATP synthase directly transfers electrons','The proton gradient is the driving force linking electron transport to ATP synthesis','Electron transport requires ATP to proceed','The Krebs cycle produces the proton gradient directly','B','The chemiosmotic theory states that electron transport pumps protons to create a gradient, and ATP synthase uses that gradient to make ATP; the two processes are coupled by the proton gradient, not directly linked.'),
('AP Biology','medium','cell-structure','In a plant cell undergoing plasmolysis, what has happened?','The cell wall has dissolved','Water has left the cell, causing the membrane to pull away from the cell wall','The vacuole has expanded excessively','Chloroplasts have migrated to the cell wall','B','Plasmolysis occurs when a plant cell in a hypertonic solution loses water by osmosis; the protoplast shrinks and pulls away from the cell wall, visible under a microscope.'),
('AP Biology','medium','cell-structure','Which of the following cell types would you expect to have the most mitochondria per unit volume?','Skin epithelial cells','Fat storage cells','Cardiac muscle cells','Pancreatic cells that store enzymes','C','Cardiac muscle cells contract continuously and require huge amounts of ATP; they have more mitochondria per unit volume than almost any other cell type.'),
('AP Biology','medium','cell-structure','What is the function of the nuclear pore complex?','Replicate DNA within the nucleus','Regulate the transport of molecules between the nucleus and cytoplasm','Synthesize ribosomal proteins in the nucleus','Anchor chromosomes during mitosis','B','Nuclear pore complexes are large protein assemblies in the nuclear envelope that selectively allow passage of molecules such as mRNA, proteins, and ribosomal subunits between the nucleus and cytoplasm.'),
('AP Biology','medium','cell-structure','Which of the following would most likely increase the fluidity of a plasma membrane?','Increasing the proportion of saturated fatty acids','Adding more cholesterol at low temperatures','Replacing unsaturated fatty acids with saturated ones','Increasing the proportion of unsaturated fatty acids','D','Unsaturated fatty acids contain double bonds that create kinks in the hydrocarbon tails, preventing tight packing and increasing membrane fluidity. More unsaturated fatty acids → more fluid membrane.'),
('AP Biology','medium','cell-structure','A cell that has been treated with a respiratory poison (blocking electron transport) continues to divide briefly. What energy source is most likely sustaining cell functions?','Photosynthesis','ATP from glycolysis','Stored ATP from the Golgi','Energy from nuclear reactions','B','When oxidative phosphorylation is blocked, glycolysis can continue to generate small amounts of ATP anaerobically, temporarily sustaining the cell.'),
('AP Biology','medium','cell-structure','How do cells regulate the number of receptors on their surface in response to high ligand concentrations?','They synthesize more receptors immediately','They down-regulate receptors through receptor-mediated endocytosis and degradation','They move receptors to the nucleus','They stop producing ATP','B','Receptor down-regulation: when ligand levels are chronically high, receptor–ligand complexes are internalized and the receptors are degraded rather than recycled, reducing cell sensitivity.'),
('AP Biology','medium','cell-structure','Which observation would most directly support the conclusion that a membrane protein is a transmembrane protein?','It is found only on the extracellular side of the membrane','It spans the hydrophobic core and can be labeled from both sides of the membrane','It is attached to the cytoskeleton','It is degraded in lysosomes','B','Demonstrating that the protein is accessible to labeling reagents on both the extracellular and cytoplasmic surfaces indicates it spans the entire bilayer.'),
('AP Biology','medium','cell-structure','A cell lacking functional Golgi apparatus would most likely have trouble with which of the following?','DNA replication','Post-translational modification and secretion of proteins','Transcription of genes','Glycolysis in the cytoplasm','B','The Golgi modifies proteins (glycosylation, phosphorylation), sorts them, and packages them into vesicles for secretion or delivery; without the Golgi, these processes fail.'),
('AP Biology','medium','cell-structure','What is the relationship between the rough ER and the nuclear envelope?','They are completely separate membranes with no connection','The outer membrane of the nuclear envelope is continuous with the rough ER membrane','The rough ER is located inside the nucleus','The nuclear envelope is derived from the Golgi apparatus','B','The outer membrane of the nuclear envelope is continuous with the rough ER membrane, forming an interconnected system of membranes; the perinuclear space connects to the ER lumen.'),
('AP Biology','medium','cell-structure','When a cell undergoes endocytosis, what happens to the plasma membrane surface area?','It increases because new membrane is added','It decreases because membrane is internalized','It stays the same because osmosis compensates','It doubles because of membrane synthesis','B','Endocytosis internalizes a portion of the plasma membrane as a vesicle, reducing the cell surface area; exocytosis adds membrane back, keeping a dynamic balance.'),
('AP Biology','medium','cell-structure','Which component of the cytoskeleton is responsible for the movement of vesicles along cellular highways?','Intermediate filaments','Actin microfilaments','Microtubules','Spectrin networks','C','Microtubules serve as tracks for motor proteins (kinesins and dyneins) that carry vesicles and organelles directionally through the cell.'),
('AP Biology','medium','cell-structure','A researcher discovers a new cell organelle surrounded by a double membrane. Which of the following is the most likely function based on this structural feature?','Synthesize lipids','Store and process genetic information (nucleus) or energy conversion (mitochondria/chloroplast)','Package proteins for secretion','Digest cellular debris','B','Double-membrane organelles include the nucleus (genetic information storage), mitochondria (ATP production), and chloroplasts (photosynthesis) — all requiring separation of their internal chemistry from the cytoplasm.'),
('AP Biology','medium','cell-structure','Why is the chemiosmotic gradient (proton motive force) essential for ATP synthesis in mitochondria?','It directly phosphorylates ADP without any enzyme','The flow of protons through ATP synthase drives rotation of its subunits, powering ATP synthesis','It denatures the electron transport proteins so they release energy','The gradient prevents electrons from reaching oxygen','B','The proton motive force drives protons through ATP synthase; this flow causes conformational changes in the F1 subunit that catalyze the synthesis of ATP from ADP and inorganic phosphate.'),
('AP Biology','medium','cell-structure','What would be the expected effect of treating cells with cytochalasin D, which prevents actin polymerization?','Cells would fail to segregate chromosomes in mitosis','Cells would be unable to undergo cytokinesis or cell migration','ATP synthesis would stop immediately','Protein secretion would be blocked','B','Actin filaments form the contractile ring for cytokinesis and are essential for lamellipodia during cell migration; inhibiting actin polymerization blocks both processes.'),
('AP Biology','medium','cell-structure','Which of the following best explains why grana (stacks of thylakoids) are advantageous in chloroplasts?','They separate the light reactions from the Calvin cycle','They increase the membrane surface area available for light-harvesting and electron transport','They store glucose produced during photosynthesis','They protect chlorophyll from ultraviolet light','B','Grana maximize the surface area of thylakoid membranes, increasing the capacity for photosystems and electron transport complexes, thus enhancing the efficiency of light-driven ATP and NADPH production.'),
('AP Biology','medium','cell-structure','A cell has a high concentration of Na+ outside and K+ inside. Which of the following correctly describes the movement of these ions at rest?','Both ions move inward by active transport','Na+ tends to diffuse in and K+ tends to diffuse out down their concentration gradients','K+ actively moves inward while Na+ passively leaves','Both ions are equally distributed and show no tendency to move','B','At rest, Na+ concentration is higher outside so it tends to diffuse inward, and K+ concentration is higher inside so it tends to diffuse outward; the Na+/K+ pump continuously counteracts these tendencies.'),
('AP Biology','medium','cell-structure','What type of transport is used when glucose enters most animal cells from blood?','Simple diffusion through the lipid bilayer','Active transport requiring direct ATP hydrolysis','Facilitated diffusion via GLUT proteins','Secondary active transport always','C','Glucose enters most animal cells via GLUT (glucose transporter) proteins by facilitated diffusion, moving down its concentration gradient without directly consuming ATP.'),
('AP Biology','medium','cell-structure','Which of the following correctly explains the function of the signal recognition particle (SRP)?','It degrades misfolded proteins in the ER','It recognizes the signal sequence on a ribosome and targets it to the rough ER','It transports mRNA from the nucleus to the ribosome','It assists in the folding of proteins in the Golgi','B','The SRP recognizes the signal sequence emerging from the ribosome and binds to it, then directs the ribosome-mRNA complex to the SRP receptor on the rough ER membrane for co-translational protein insertion.'),
('AP Biology','medium','cell-structure','In terms of membrane permeability, which of the following molecules would diffuse most slowly across a pure phospholipid bilayer?','O2','CO2','Ethanol','Na+ ions','D','Ions like Na+ are charged and hydrophilic; the hydrophobic core of the bilayer strongly repels charged particles, making unaided diffusion of ions extremely slow compared to small nonpolar molecules.'),
('AP Biology','medium','cell-structure','Why do cells need to maintain membrane asymmetry (different lipids/proteins on each leaflet)?','To allow the membrane to dissolve lipid-soluble molecules','Different surfaces interact with different environments — extracellular vs. cytoplasmic signaling','Both leaflets are identical for uniform strength','Asymmetry increases membrane rigidity uniformly','B','Membrane asymmetry means the outer leaflet has different lipids and glycoproteins for extracellular signaling and recognition, while the inner leaflet has lipids involved in cytoplasmic signal transduction.'),
('AP Biology','medium','cell-structure','A cell biologist finds that without the enzyme catalase, cells accumulate toxic levels of hydrogen peroxide. In which organelle is catalase normally located?','Mitochondria','Lysosome','Peroxisome','Golgi apparatus','C','Catalase is a key enzyme in peroxisomes that converts hydrogen peroxide (generated during fatty acid oxidation) into water and oxygen, protecting the cell from oxidative damage.'),
('AP Biology','medium','cell-structure','Which of the following would you predict about a cell that secretes large quantities of digestive enzymes?','It would have few ribosomes','It would have an extensive rough ER and large Golgi','It would rely heavily on smooth ER for enzyme production','It would have a decreased number of mitochondria','B','Digestive enzymes are proteins; their secretion requires extensive rough ER (for synthesis) and a large Golgi apparatus (for modification, packaging, and targeting to secretory vesicles).'),
('AP Biology','medium','cell-structure','What happens to the plasma membrane during phagocytosis?','It ruptures to allow the particle inside','Pseudopods extend and engulf the particle, pulling membrane inward as a phagosome','The nucleus opens to admit the particle','Exocytosis releases digestive enzymes to digest the particle outside','B','During phagocytosis, actin-driven pseudopods extend around the target particle and fuse, internalizing it in a phagosome that will fuse with lysosomes for digestion.'),
('AP Biology','medium','cell-structure','A cell is treated with a drug that blocks all vesicle trafficking from the ER to the Golgi. Which of the following would most likely accumulate?','Glucose in the cytoplasm','Unprocessed proteins in the ER lumen','Mature secretory proteins at the plasma membrane','Ribosomal subunits in the nucleus','B','If ER-to-Golgi transport is blocked, newly synthesized secretory and membrane proteins that enter the ER cannot move forward in the secretory pathway and accumulate in the ER lumen.'),

-- ============================================================
-- CELL STRUCTURE — HARD (48 questions)
-- ============================================================
('AP Biology','hard','cell-structure','A researcher creates a cell with a mutation in the gene encoding the β-subunit of ATP synthase, preventing rotation of the rotor. The cells are provided with glucose. Which of the following would be the expected outcome?','Glycolysis would stop immediately because it requires ATP synthase','The proton gradient across the inner mitochondrial membrane would be more negative than normal','ATP would still be produced at normal levels via substrate-level phosphorylation in glycolysis and the Krebs cycle only','The electron transport chain would accelerate to compensate','C','Glycolysis and the Krebs cycle produce ATP via substrate-level phosphorylation independent of ATP synthase; only oxidative phosphorylation depends on ATP synthase. These pathways would continue but total ATP yield would be dramatically reduced.'),
('AP Biology','hard','cell-structure','An experiment shows that collapsing the proton gradient with a proton ionophore (allowing protons to cross the inner membrane freely) dissipates body heat in brown adipose tissue. Which protein mediates this effect and what is the biological significance?','ATP synthase; allows rapid ATP synthesis for heat production','Uncoupling protein 1 (UCP1/thermogenin); allows proton leak that generates heat instead of ATP','Cytochrome c; releases electrons directly as heat','Complex I; reverses electron flow to generate heat','B','UCP1 in the inner mitochondrial membrane of brown adipose tissue allows protons to flow back without passing through ATP synthase, dissipating the proton gradient as heat — essential for non-shivering thermogenesis in newborns and hibernating animals.'),
('AP Biology','hard','cell-structure','In an experiment, cells are pulse-labeled with radioactive amino acids for 5 minutes, then chased with unlabeled amino acids for 30 minutes. Radioactivity is measured in different compartments over time. The correct order in which radioactivity would appear in secretory compartments is:','Nucleus → ER → Golgi → vesicles → extracellular','Rough ER → cis-Golgi → trans-Golgi → secretory vesicles → extracellular space','Smooth ER → lysosome → plasma membrane → extracellular','Free ribosomes → peroxisome → Golgi → nucleus','B','Secretory proteins follow the endomembrane pathway: synthesized at rough ER, transported to the cis face of Golgi, modified through medial and trans cisternae, packaged into secretory vesicles, and released by exocytosis.'),
('AP Biology','hard','cell-structure','A student discovers a unicellular organism with a double-stranded circular chromosome, 70S ribosomes, no nuclear membrane, and a peptidoglycan cell wall. A second organism has linear chromosomes, 80S ribosomes, a nuclear membrane, and a cell wall made of chitin. What are these organisms, respectively?','Virus; plant','Archaeon; animal','Bacterium; fungus','Prokaryote; plant','C','The first organism matches bacterial features (circular DNA, 70S ribosomes, no nucleus, peptidoglycan wall). The second matches a fungus (linear chromosomes, 80S ribosomes, nuclear membrane, chitin wall).'),
('AP Biology','hard','cell-structure','In a cell-free translation system, a secretory protein is synthesized normally. However, when microsomal membranes (ER vesicles) are added after translation is complete, the protein fails to enter the ER lumen. What does this demonstrate?','Proteins can enter the ER at any time after synthesis','Co-translational translocation is required; the signal sequence must be recognized while the protein is still being synthesized','Microsomal membranes inhibit protein folding','The protein requires ATP to enter the ER post-translationally','B','Co-translational insertion requires the SRP to recognize the signal sequence as it emerges from the ribosome; if translation is complete before membranes are present, the signal sequence is buried and cannot engage the translocon.'),
('AP Biology','hard','cell-structure','A researcher knocks out the gene for dynein in a cell. Which of the following functions would be most directly impaired?','Actin-based cell migration','Retrograde vesicle transport along microtubules (toward the cell body/minus end)','Clathrin-coated pit formation','SNARE-mediated vesicle fusion','B','Dynein is a minus-end-directed microtubule motor protein responsible for retrograde transport (from cell periphery toward the nucleus/centrosome) and for moving chromosomes on the spindle.'),
('AP Biology','hard','cell-structure','A new antibiotic is found to disrupt the peptidoglycan synthesis of bacterial cell walls. Which of the following would be a predicted consequence in bacteria but NOT in human cells, and why?','Human cells lack plasma membranes, so they are unaffected','Bacteria would undergo osmotic lysis because they lack a cell wall to resist osmotic pressure, while human cells have no cell wall to begin with','Human cells have chitin walls that the antibiotic cannot disrupt','Bacteria and human cells would both lyse equally','B','Bacteria require their peptidoglycan cell wall to resist osmotic pressure; without it, they undergo osmotic lysis in hypotonic environments. Human cells lack a cell wall entirely, so they are unaffected by drugs targeting peptidoglycan synthesis (e.g., penicillin).'),
('AP Biology','hard','cell-structure','In an experiment measuring membrane potential, a researcher finds that treating a neuron with ouabain (which inhibits the Na+/K+ ATPase) causes the resting membrane potential to gradually depolarize to zero. Which of the following best explains this outcome?','Ouabain directly opens voltage-gated Na+ channels','Without the pump, Na+ accumulates inside and K+ depletes outside, collapsing the ion gradients that create the resting potential','The pump directly generates the membrane potential by moving charges','Ouabain activates K+ leak channels that depolarize the membrane','B','The resting membrane potential depends on ion gradients maintained by the Na+/K+ pump; inhibiting the pump allows Na+ to accumulate inside and K+ to deplete, eventually collapsing the gradients and depolarizing the membrane.'),
('AP Biology','hard','cell-structure','A cell biologist studying membrane composition finds that treating membranes with methyl-β-cyclodextrin (which extracts cholesterol) causes membrane proteins to lose their organized clustering. What does this suggest about membrane organization?','Cholesterol is required for phospholipid synthesis','Cholesterol-rich lipid rafts organize signaling proteins into functional domains','Removing cholesterol increases membrane permeability to ions uniformly','Cholesterol directly cross-links membrane proteins','B','Lipid rafts are cholesterol- and sphingomyelin-rich microdomains that concentrate specific membrane proteins (especially signaling proteins); removing cholesterol disrupts these rafts and disperses the proteins.'),
('AP Biology','hard','cell-structure','In an experiment, mitochondria are isolated and the inner membrane is disrupted to release matrix contents. When the membrane is reassembled with ATP synthase oriented in reverse (F1 subunit facing the intermembrane space), what would be predicted?','ATP would be synthesized at double the normal rate','ATP would be hydrolyzed when protons flow from the matrix to the intermembrane space (reversed proton flow drives ATP hydrolysis)','The ETC would reverse and consume NADH','No effect, as ATP synthase works in both orientations','B','Reversing the orientation of ATP synthase would mean protons flowing in the normal direction would now drive the enzyme in reverse (ATP hydrolysis), not synthesis; ATP synthesis requires protons to flow from intermembrane space to matrix through the correctly oriented enzyme.'),
('AP Biology','hard','cell-structure','A student designs an experiment where they label phospholipids on the outer leaflet of the plasma membrane with a fluorescent tag. After 24 hours, they find the fluorescent label on the inner leaflet as well. What process accounts for this?','Simple diffusion of phospholipids through the bilayer','Lipid flip-flop (transverse diffusion) catalyzed by flippase enzymes','Endocytosis and exocytosis cycling','Membrane fusion with organelles','B','Spontaneous flip-flop of phospholipids between leaflets is extremely slow; the observed movement is catalyzed by flippases (phospholipid translocases) that actively move phospholipids from one leaflet to the other, maintaining membrane asymmetry.'),
('AP Biology','hard','cell-structure','Research shows that cells with mutations in Rab GTPase proteins misroute vesicles to incorrect compartments. What does this tell us about vesicle targeting?','SNARE proteins alone determine all vesicle specificity','Rab proteins provide an additional layer of specificity by tethering vesicles to the correct target membrane before SNARE pairing','The Golgi randomly sorts vesicles','Vesicle targeting depends only on lipid composition','B','Rab GTPases act in concert with tethering factors to capture vesicles at the correct target membrane; this tethering facilitates subsequent SNARE complex assembly, creating a two-step specificity mechanism.'),
('AP Biology','hard','cell-structure','A cell is undergoing apoptosis. During this process, phosphatidylserine, normally restricted to the inner leaflet, appears on the outer leaflet. How does this occur and what is its significance?','Flippases are activated to increase flip-flop; it signals for cell division','Scramblases are activated that randomize phospholipid distribution; exposed phosphatidylserine serves as an "eat-me" signal for phagocytes','The membrane ruptures and phospholipids redistribute randomly','ATP synthase reverses and catalyzes lipid translocation','B','During apoptosis, scramblase enzymes are activated (and flippase is inactivated), causing phosphatidylserine to appear on the outer leaflet. This "eat-me" signal is recognized by macrophages that phagocytose the apoptotic cell.'),
('AP Biology','hard','cell-structure','An experiment measures the rate of CO2 production in isolated mitochondria given different substrates. Adding malonate (a competitive inhibitor of succinate dehydrogenase) causes CO2 production to decrease but not stop. What does this indicate?','Succinate dehydrogenase is the only enzyme in the Krebs cycle','Other Krebs cycle substrates continue to generate CO2 even when succinate dehydrogenase is inhibited','Malonate blocks the entire electron transport chain','CO2 is produced only by pyruvate decarboxylation','B','The Krebs cycle has multiple steps that release CO2 (isocitrate dehydrogenase, α-ketoglutarate dehydrogenase); blocking only succinate dehydrogenase reduces but does not eliminate CO2 production from other cycle steps.'),
('AP Biology','hard','cell-structure','A researcher observes that cells treated with brefeldin A (BFA), which disrupts Golgi structure, show a redistribution of Golgi membrane proteins back into the ER. What does this suggest about the relationship between these compartments?','The ER and Golgi are completely separate and independent compartments','There is a continuous cycle of membrane flow between the ER and Golgi that BFA disrupts by blocking anterograde transport','BFA directly inserts Golgi proteins into the ER','The Golgi synthesizes proteins that are then imported into the ER','B','BFA blocks COPI vesicle formation, stopping anterograde ER-to-Golgi transport while retrograde transport continues; this causes Golgi membrane proteins to be swept back into the ER, revealing the dynamic equilibrium between these compartments.'),
('AP Biology','hard','cell-structure','In a plant cell, the large central vacuole occupies up to 90% of cell volume. How does this benefit the plant, and what would happen if the tonoplast became freely permeable to all ions?','It reduces metabolic costs; free permeability would increase photosynthesis','Reduces cytoplasmic volume needed while maintaining turgor; free ion permeability would collapse the osmotic gradient and cause loss of turgor (wilting)','The vacuole stores DNA; free permeability would release DNA into cytoplasm','It houses ribosomes; free permeability would disrupt translation','B','The vacuole maintains turgor pressure and stores metabolites; the tonoplast selectively controls ion movement to maintain osmotic gradients. If freely permeable, osmotic gradients would collapse, turgor would be lost, and the plant would wilt.'),
('AP Biology','hard','cell-structure','A researcher studying endocytosis finds that cells expressing a dominant-negative dynamin (which cannot hydrolyze GTP) are unable to complete endocytosis. What does this reveal about dynamin''s role?','Dynamin synthesizes clathrin-coated pits','Dynamin''s GTP hydrolysis provides the mechanical force to pinch off and release endocytic vesicles from the plasma membrane','Dynamin is a motor protein that moves vesicles along microtubules','Dynamin degrades the clathrin coat after endocytosis','B','Dynamin is a GTPase that forms a ring around the neck of a forming vesicle; GTP hydrolysis drives a conformational change that pinches off (scissions) the vesicle from the plasma membrane, completing endocytosis.'),
('AP Biology','hard','cell-structure','A cell has a mutation that prevents the addition of mannose-6-phosphate to lysosomal enzymes. What would be the consequence, and what disease does this model?','Lysosomal enzymes would be hyperactive, digesting all cellular components','Lysosomal enzymes would be secreted outside the cell instead of targeted to lysosomes, causing I-cell disease (mucolipidosis II)','Lysosomes would multiply abnormally','The Golgi would be destroyed by misrouted enzymes','B','Mannose-6-phosphate is the lysosomal targeting signal; without it, lysosomal enzymes are not recognized by M6P receptors in the Golgi and are instead secreted. This causes I-cell disease, where substrates accumulate in cells because lysosomes lack their digestive enzymes.'),
('AP Biology','hard','cell-structure','What would happen if a cell''s proteasome were experimentally inactivated while the cell was under conditions that produce many misfolded proteins?','Misfolded proteins would be secreted','Misfolded proteins tagged with ubiquitin would accumulate in the cytoplasm, leading to proteotoxic stress and cell death','Ribosomes would stop synthesizing proteins','The ER would increase its protein folding capacity','B','The proteasome degrades ubiquitin-tagged proteins; if inactivated, misfolded proteins that are normally cleared accumulate in the cytoplasm, leading to proteotoxic stress and eventually cell death (as seen in some neurodegenerative diseases).'),
('AP Biology','hard','cell-structure','A student treats a plant cell with high concentrations of propionic acid (a membrane-permeable weak acid). Explain what would happen to the cell''s cytoplasmic pH and its consequences on cellular function.','The acid would stay outside the cell; no effect on cytoplasm','The uncharged acid crosses the membrane and releases protons in the cytoplasm, lowering cytoplasmic pH, inhibiting enzymes and metabolic processes','The acid would be neutralized by the cell wall','The acid would be actively pumped out immediately without effect','B','Membrane-permeable weak acids (propionic acid) cross the lipid bilayer in their uncharged form, then dissociate inside the cell releasing H+, acidifying the cytoplasm, denaturing enzymes and disrupting metabolic processes.'),
('AP Biology','hard','cell-structure','In an experimental system, a protein is found to move from the ER lumen to the nucleus. Is this possible, and by what mechanism?','Yes, any protein can freely diffuse from the ER to the nucleus through the cytoplasm','Yes, but only if the protein contains a nuclear localization signal (NLS) that is recognized after it retrotranslocates from the ER into the cytoplasm','No, the ER and nucleus are separate compartments with no communication','Yes, through direct connection between ER membrane and inner nuclear membrane','B','Proteins can exit the ER via retrotranslocation (ERAD pathway); if a retrotranslocated protein contains an NLS, importins can recognize it in the cytoplasm and transport it through nuclear pore complexes into the nucleus.'),
('AP Biology','hard','cell-structure','An experiment shows that cells treated with nocodazole (depolymerizes microtubules) have Golgi fragments dispersed throughout the cytoplasm rather than localized near the centrosome. What does this reveal about Golgi positioning?','The Golgi membrane directly binds to the centrosome','Microtubule-based motor proteins (dyneins) transport Golgi elements toward the minus end of microtubules at the centrosome','The Golgi fragments are moved by actin-myosin to the centrosome','Golgi positioning is random and has no functional significance','B','The Golgi is maintained near the centrosome by dynein-mediated transport along microtubules toward their minus ends; disrupting microtubules releases this positioning, scattering Golgi fragments throughout the cell.'),
('AP Biology','hard','cell-structure','How do plant cells avoid bursting in freshwater environments even though they contain many dissolved solutes (making the environment hypotonic relative to the cell)?','Plant cells pump out solutes to equalize concentrations','The rigid cell wall limits cell expansion; as water enters, turgor pressure builds until it equals the osmotic gradient, reaching water potential equilibrium','Plant cells have fewer aquaporins than animal cells','Plant cell membranes are impermeable to water','B','The cell wall limits expansion; as water enters and turgor pressure (pressure potential) increases, the water potential inside the cell increases until it equals the water potential outside, stopping net water movement. The cell reaches turgor without bursting.'),
('AP Biology','hard','cell-structure','A new drug is found to dissolve the glycocalyx (sugar coat) on the outer surface of animal cells. Which of the following would be a predicted consequence?','The cell would immediately lyse','Cell-cell recognition, immune surveillance, and protection from mechanical damage would be impaired','Protein synthesis would stop','Mitochondrial function would be directly disrupted','B','The glycocalyx (carbohydrate chains of glycoproteins and glycolipids) mediates cell-cell recognition, protects the cell surface from mechanical damage, and is recognized by immune cells; disrupting it impairs all of these functions.'),
('AP Biology','hard','cell-structure','In mitosis, sister chromatids are separated by microtubule depolymerization at the kinetochore end. How does this create movement?','ATP hydrolysis by kinesin motors pulls chromosomes','Depolymerization of kinetochore microtubules shortens them from the chromosome attachment end, pulling chromosomes poleward (Pac-Man mechanism)','Motor proteins push chromosomes away from the equator','Actin filaments contract to pull chromosomes','B','During anaphase A, kinetochore microtubules depolymerize at the kinetochore (plus end), and the chromosome remains attached via the kinetochore complex; as the microtubule shrinks, it pulls the chromosome toward the pole (the "Pac-Man" model).'),
('AP Biology','hard','cell-structure','A researcher finds that cells with a mutation preventing nuclear lamina assembly have fragile nuclei that rupture during cell migration. What does this suggest about the nuclear lamina?','The nuclear lamina synthesizes DNA','The nuclear lamina (intermediate filaments lining the inner nuclear membrane) provides mechanical integrity to the nucleus','The nuclear lamina is required for mRNA export','The nuclear lamina is responsible for chromatin transcription','B','The nuclear lamina is a meshwork of lamin intermediate filaments attached to the inner nuclear membrane that gives the nucleus its shape and mechanical stiffness, protecting the genome during cell deformation.'),
('AP Biology','hard','cell-structure','Explain why a cell with a highly branched rough ER network and many mitochondria near the ER would be expected to have a high rate of protein secretion.','Branched ER reduces protein synthesis','More ER membrane means more ribosomes and more protein synthesis; nearby mitochondria supply ATP needed for the energy-intensive processes of translation, protein folding, and vesicular transport','More mitochondria near ER means more CO2 is produced, stimulating protein synthesis','The rough ER supplies electrons to mitochondria for ATP synthesis','B','Extensive rough ER provides large surface area for ribosome attachment (and thus high translation capacity); proximity of mitochondria ensures rapid ATP supply for the energetically demanding processes of protein synthesis, chaperone-assisted folding, and vesicular trafficking.'),
('AP Biology','hard','cell-structure','A researcher studying cellular energy metabolism finds that dinitrophenol (DNP) causes weight loss by increasing metabolic rate. DNP is a proton ionophore that shuttles protons across the inner mitochondrial membrane. How does this explain its effect?','DNP inhibits glycolysis, forcing cells to burn fat for ATP synthesis','DNP dissipates the proton gradient, uncoupling electron transport from ATP synthesis; electrons continue flowing and O2 is consumed, but energy is released as heat rather than stored as ATP, increasing metabolic rate','DNP activates ATP synthase, producing excess ATP that is converted to heat','DNP blocks the Krebs cycle, forcing ATP production from fat oxidation alone','B','As an uncoupler, DNP allows protons to bypass ATP synthase, collapsing the gradient and releasing its energy as heat. To maintain cellular ATP levels, cells oxidize more fuel (burning more calories), which is why DNP causes weight loss — at the dangerous cost of hyperthermia.'),
('AP Biology','hard','cell-structure','In an experiment testing membrane fusion, researchers find that mixing lipid vesicles alone rarely results in fusion, but vesicles bearing v-SNARE proteins fuse specifically with membranes bearing the complementary t-SNARE proteins. What principle does this demonstrate?','Membrane fusion is purely driven by lipid composition','SNARE protein complementarity provides the specificity and energy for membrane fusion, explaining how cells target vesicle delivery precisely','Any protein on a vesicle is sufficient to cause fusion','Lipid bilayers are inherently unstable and require proteins only to slow fusion','B','Complementary SNARE protein pairing (v-SNARE + t-SNARE forming a tight 4-helix bundle) both provides specificity (only matched SNAREs pair) and supplies the mechanical force that overcomes the energy barrier to membrane fusion.'),
('AP Biology','hard','cell-structure','A genetic screen in yeast identifies a mutant that accumulates secretory vesicles near the cell surface but fails to secrete their contents. The mutation is in a gene encoding a calcium-sensitive protein. What does this suggest?','Calcium signaling is required for vesicle formation at the Golgi','Calcium influx likely triggers the final step of vesicle–plasma membrane fusion (exocytosis) by activating the calcium sensor protein','Calcium is needed for protein synthesis in the ER','The mutation affects microtubule-based vesicle transport','B','In regulated secretion, calcium influx triggers the fusion of docked, primed secretory vesicles with the plasma membrane by activating calcium-sensing proteins (like synaptotagmin in neurons); vesicles accumulate at the surface but cannot fuse without calcium signaling.'),
('AP Biology','hard','cell-structure','Cells in the kidney collecting duct insert aquaporin-2 (AQP2) channels into their apical membranes in response to ADH (vasopressin). This is an example of which cellular mechanism, and what is its physiological consequence?','Receptor-independent constitutive secretion; increases solute reabsorption','Signal-regulated exocytosis of intracellular vesicles bearing AQP2 to the apical membrane; increases water reabsorption from urine','Endocytosis of AQP2 from the blood; decreases water loss','Direct synthesis of new AQP2 protein in response to ADH; immediate water reabsorption','B','ADH binds receptors, activating cAMP/PKA signaling that causes intracellular vesicles loaded with AQP2 to fuse with the apical membrane by exocytosis; more aquaporins in the membrane increase water permeability, allowing water reabsorption and concentrating the urine.'),
('AP Biology','hard','cell-structure','What would be the consequence of a mutation in the KDEL retention signal of an ER-resident protein?','The protein would be retained in the Golgi permanently','The protein would be secreted outside the cell instead of being retained in the ER lumen','The protein would be degraded by proteasomes','The protein would move to the nucleus','B','KDEL is a C-terminal amino acid sequence recognized by KDEL receptors in the Golgi that retrieve escaped ER-resident proteins via COPI vesicles back to the ER; loss of KDEL results in the protein being secreted constitutively.'),
('AP Biology','hard','cell-structure','In a cell-fusion experiment, human cells and mouse cells are fused. Initially, human and mouse membrane proteins are separated on opposite sides of the hybrid cell. After 40 minutes at 37°C, the proteins are fully intermingled. Lowering the temperature to 4°C before fusion prevents intermixing. What does this demonstrate?','Membrane proteins are actively sorted by the Golgi after fusion','Membrane proteins can diffuse laterally in the fluid lipid bilayer; low temperature decreases lipid fluidity and prevents diffusion','Human and mouse cells have identical proteins that mix randomly','Membrane proteins are transported by vesicles after cell fusion','B','This classic Frye and Edidin experiment demonstrated that membrane proteins diffuse laterally in the lipid bilayer (fluid mosaic model); reducing temperature solidifies the bilayer and stops diffusion, showing that protein mixing is due to lateral diffusion in a fluid membrane.'),
('AP Biology','hard','cell-structure','A researcher studying organelle biogenesis proposes that peroxisomes can form de novo from the ER as well as by division of pre-existing peroxisomes. What evidence would best support the de novo pathway?','Peroxisomes divide faster than mitochondria','When all peroxisomes are eliminated from a cell, new peroxisomes with correct protein composition emerge from the ER in a process blocked by ER-export inhibitors','Peroxisome membranes are identical to Golgi membranes','Peroxisomal proteins are synthesized on rough ER ribosomes','B','Demonstrating that new peroxisomes appear from ER-derived vesicles (and that this is blocked by blocking ER export) would confirm de novo biogenesis; showing this occurs after total peroxisome elimination rules out division as the sole source.'),
('AP Biology','hard','cell-structure','A cell is treated simultaneously with oligomycin (ATP synthase inhibitor) and 2-deoxyglucose (glycolysis inhibitor). What would happen to cellular ATP levels and why?','ATP would increase because fatty acid oxidation is upregulated','ATP levels would drop precipitously because both major ATP-producing pathways are blocked','ATP would be maintained by the pentose phosphate pathway alone','ATP synthase would switch to using fatty acids as fuel','B','Oligomycin blocks oxidative phosphorylation (the major ATP source) and 2-deoxyglucose blocks glycolysis (the backup); with both pathways inhibited, cells rapidly deplete ATP, halting energy-requiring processes.'),
('AP Biology','hard','cell-structure','Why is it important that the proton gradient in mitochondria is maintained across an otherwise impermeable membrane? What would happen if the inner membrane had a moderate but nonzero baseline permeability to protons?','Proton impermeability is not necessary; any membrane can sustain ATP synthesis','The impermeability concentrates the proton gradient; even moderate proton leak dissipates the gradient and reduces coupling efficiency (less ATP per O2 consumed), acting as a natural uncoupler','Proton leak would accelerate ATP synthesis by increasing proton flow through ATP synthase','The inner membrane is permeable; proton gradients are maintained by active transport of protons out of the matrix','B','The proton gradient stores energy as potential; any proton leak that bypasses ATP synthase dissipates this energy as heat rather than converting it to ATP, reducing the P/O ratio (ATP made per oxygen consumed) — this is why natural uncoupling proteins reduce ATP yield.'),
('AP Biology','hard','cell-structure','An experimentally induced deletion of the ERAD (ER-associated degradation) pathway causes accumulation of misfolded proteins in the ER lumen. What would you expect to happen to UPR (unfolded protein response) signaling?','UPR signaling would be suppressed because ERAD and UPR inhibit each other','UPR signaling would be chronically activated because the accumulation of misfolded proteins that ERAD normally clears would continuously signal ER stress','UPR would be activated once and then permanently shut off','ERAD deletion would activate apoptosis without engaging UPR','B','ERAD normally clears misfolded proteins from the ER, relieving ER stress; without ERAD, misfolded proteins accumulate and chronically activate UPR sensors (IRE1, PERK, ATF6), eventually triggering apoptosis if stress is unresolvable.'),
('AP Biology','hard','cell-structure','A researcher inserts a large, rigidly folded protein domain into the middle of a transmembrane helix of a membrane protein. What would be the predicted effect on membrane insertion?','The domain would be cleaved off during insertion','The large folded domain would prevent the helix from spanning the hydrophobic bilayer, disrupting its topology and likely causing the protein to misfold or be retained in the ER','The protein would insert with the domain facing the cytoplasm','Folded domains always insert into membranes if hydrophobic enough','B','Transmembrane helices must thread through the narrow hydrophobic translocon channel in the ER membrane; a large folded domain inserted within the helix would be too bulky to pass through, disrupting proper membrane topology and likely triggering ER quality control.'),
('AP Biology','hard','cell-structure','An evolutionary biologist notes that the sequences of genes encoded in mitochondrial DNA are most similar to those found in α-proteobacteria. What does this support, and what evidence would refute endosymbiotic theory?','It supports abiogenesis of mitochondria; finding mitochondria with nuclear DNA would refute it','It supports endosymbiotic theory; finding that mitochondrial ribosomes are 80S (eukaryotic) rather than 70S (prokaryotic) would refute it','It supports endosymbiotic theory; finding no bacteria with double membranes would refute it','It supports convergent evolution of energy metabolism','B','The endosymbiotic theory predicts mitochondria descended from α-proteobacterial ancestors; 70S mitochondrial ribosomes (bacterial-type) are key evidence. Finding 80S ribosomes would suggest a eukaryotic origin and undermine the endosymbiotic model.'),
('AP Biology','hard','cell-structure','In the context of membrane lipid composition, explain how bacteria living in cold Arctic waters maintain membrane fluidity appropriate for their environment.','They produce heat shock proteins to prevent membrane solidification','They increase the proportion of unsaturated fatty acids in their membrane phospholipids, which lower the melting temperature and maintain fluidity at low temperatures','They increase the proportion of saturated fatty acids','They add cholesterol to their membranes like eukaryotes','B','Cold temperatures reduce membrane fluidity; bacteria (which lack cholesterol) compensate by increasing unsaturated fatty acids, which have kinked tails that prevent tight packing, maintaining membrane fluidity in cold environments — an example of homeoviscous adaptation.'),
('AP Biology','hard','cell-structure','A researcher creates an artificial cell with only a lipid bilayer, ATP synthase, and bacteriorhodopsin (a light-driven proton pump). When illuminated, ATP is produced. What principle does this confirm?','ATP synthesis requires a specific lipid bilayer composition','The chemiosmotic theory: a proton gradient across any membrane containing ATP synthase is sufficient to drive ATP synthesis, regardless of how the gradient was created','ATP synthase requires the specific proteins of the electron transport chain','Light energy is directly converted to ATP without a proton gradient','B','This classic experiment by Racker and Stoeckenius confirmed the chemiosmotic theory: ATP synthase only needs a proton gradient (regardless of its source) to synthesize ATP; bacteriorhodopsin creates the gradient using light rather than the ETC.'),
('AP Biology','hard','cell-structure','A newly discovered toxin blocks the fusion of lysosomes with late endosomes by inactivating Rab7 GTPase. What is the most likely consequence for cells exposed to this toxin?','Protein synthesis would be immediately blocked','Cargo delivered by endocytosis would not be degraded, accumulating in late endosomes and impairing receptor recycling and nutrient acquisition','Cells would immediately undergo apoptosis','Exocytosis would be constitutively activated','B','Rab7 mediates late endosome–lysosome fusion; inhibiting it traps cargo in late endosomes that cannot be degraded, preventing recycling of receptors (like LDL receptor) and digestion of nutrients and pathogens, impairing multiple cellular functions.'),
('AP Biology','hard','cell-structure','In an experiment measuring the rate of facilitated diffusion via GLUT1, increasing glucose concentration outside the cell initially increases transport rate but eventually reaches a plateau. Explain this kinetic behavior in terms of the mechanism.','GLUT1 channels widen to allow more glucose as concentration increases','The plateau reflects saturation of the fixed number of GLUT1 carrier proteins; all transporters are occupied and cycling at maximum rate (Vmax), so adding more glucose cannot further increase transport','Glucose begins simple diffusion through the bilayer at high concentrations','The plateau is caused by product inhibition of glucose inside the cell','B','Carrier-mediated transport shows saturation kinetics: at low substrate concentrations, rate increases with concentration; at high concentrations, all carrier molecules are occupied and cycling at maximum rate, so the transport rate plateaus at Vmax — analogous to enzyme kinetics.'),
('AP Biology','hard','cell-structure','A protein destined for the outer mitochondrial membrane is synthesized in the cytoplasm. Describe the targeting and insertion pathway it would use.','It enters through a nuclear pore and then moves to the mitochondria','It is inserted into the ER membrane first, then transferred to mitochondria','It contains an outer membrane targeting sequence recognized by the TOM (translocase of outer membrane) complex, which inserts it directly into the outer membrane','It is translated on rough ER ribosomes and vesicle-transported to mitochondria','C','Most mitochondrial outer membrane proteins are translated by free cytoplasmic ribosomes and contain targeting signals recognized by the TOM complex, which inserts them into the outer membrane; they do not enter the ER or use the secretory pathway.'),
('AP Biology','hard','cell-structure','Why is the pH in the lysosome maintained at approximately 4.5-5.0, and what would happen to lysosomal function if the pH rose to 7.0?','Acidic pH prevents membrane lipid degradation; pH 7.0 would accelerate digestion','The acid pH optimizes lysosomal hydrolase activity and kills pathogens; at pH 7.0, the hydrolases would be largely inactivated, blocking degradation and causing substrate accumulation','Acidic pH is maintained to concentrate protons for ATP synthesis; pH 7.0 would stop ATP production','Acid pH drives osmotic gradients; pH 7.0 would cause the lysosome to burst','B','Lysosomal hydrolases have acid pH optima; they are inactive at neutral pH. Raising lysosomal pH (as do drugs like chloroquine) inactivates these enzymes, blocking degradation of endocytosed cargo and autophagic substrates.'),
('AP Biology','hard','cell-structure','A cell biologist discovers that a protein associated with the cytoplasmic face of the Golgi membrane uses GTP hydrolysis to coat vesicles that bud from the Golgi for retrograde transport to the ER. What type of vesicle coat does this describe?','Clathrin coat','COPII coat','COPI coat','Dynamin ring','C','COPI-coated vesicles mediate retrograde transport from the Golgi back to the ER (and between Golgi cisternae); the COPI coat proteins (coatomers) are recruited by the ADP-ribosylation factor (ARF) GTPase and facilitate vesicle budding.'),
('AP Biology','hard','cell-structure','An organism is discovered that lacks a Golgi apparatus. Given the functions of the Golgi, which of the following cellular activities would most likely be impaired?','DNA replication','Glycosylation of proteins, sorting to correct compartments, and secretion of modified proteins to the cell surface','ATP synthesis in the cytoplasm','Transcription of ribosomal RNA','B','The Golgi is essential for glycosylation, sulfation, and phosphorylation of proteins, as well as sorting proteins to lysosomes, the plasma membrane, or secretory vesicles; without it, these modification and targeting functions would fail.'),
('AP Biology','hard','cell-structure','A student proposes that the cell could save energy by allowing ions to reach equilibrium across the plasma membrane rather than spending ATP to maintain gradients. Evaluate this proposal in terms of cell function.','This would be beneficial; cells waste energy maintaining unnecessary gradients','This would be catastrophic: ion gradients power secondary active transport, nerve impulses, muscle contraction, and mitochondrial ATP synthesis; losing them would stop nearly all cellular activity','Ion gradients are only important in nerve cells; other cells could function at equilibrium','Cells already allow ions to reach equilibrium; pumps only compensate for minor leaks','B','Ion gradients (especially Na+, K+, H+) are the energy currency for secondary active transport, electrochemical signaling, and the proton motive force; letting them equilibrate would collapse these processes, just as poisoning the Na+/K+ pump is lethal to cells.');
,
-- ============================================================
-- GENETICS — EASY (48 questions)
-- ============================================================
('AP Biology','easy','genetics','What is a gene?','A segment of protein that codes for DNA','A segment of DNA that codes for a functional product such as a protein','A type of RNA molecule','A chromosome segment with no function','B','A gene is a specific sequence of DNA nucleotides that encodes instructions for making a functional product, most commonly a protein, which determines traits.'),
('AP Biology','easy','genetics','What are alleles?','Different chromosomes in a cell','Alternative versions of a gene at the same locus','All the genes in an organism','Identical copies of DNA','B','Alleles are alternate forms of a gene that can exist at the same locus (location) on homologous chromosomes, potentially producing different phenotypes.'),
('AP Biology','easy','genetics','If an organism has two identical alleles for a trait, it is described as:','Heterozygous','Homozygous','Codominant','Recessive','B','An organism is homozygous when both alleles at a given locus are identical (either both dominant or both recessive).'),
('AP Biology','easy','genetics','In Mendel''s law of segregation, what happens to allele pairs during gamete formation?','They fuse together into one allele','They separate so each gamete receives one allele','They duplicate and both go to the same gamete','They are destroyed and remade','B','During meiosis, the two alleles of each gene separate (segregate) so that each gamete receives only one allele for each gene — the foundation of Mendelian inheritance.'),
('AP Biology','easy','genetics','What is the phenotype of an organism?','The genetic makeup of the organism','The observable physical or biochemical characteristics of an organism','The number of chromosomes in each cell','The sequence of nucleotides in its DNA','B','The phenotype is the observable expression of an organism''s genotype, including physical traits, biochemical characteristics, and behaviors.'),
('AP Biology','easy','genetics','What does it mean for an allele to be dominant?','It is more common in the population','Its trait is expressed even when only one copy is present','It always produces the healthiest phenotype','It is always located on the X chromosome','B','A dominant allele is expressed in the phenotype whenever it is present, whether in one copy (heterozygous) or two copies (homozygous dominant), masking the effect of the recessive allele.'),
('AP Biology','easy','genetics','In a monohybrid cross between two heterozygous parents (Aa × Aa), what is the expected phenotypic ratio in offspring?','1:1','2:1','3:1','4:1','C','A Punnett square for Aa × Aa gives AA, Aa, Aa, aa — three offspring with the dominant phenotype for every one with the recessive phenotype, a 3:1 ratio.'),
('AP Biology','easy','genetics','What is the genotypic ratio from a cross of Aa × Aa?','1 AA : 2 Aa : 1 aa','1 AA : 1 aa','2 AA : 2 aa','3 Aa : 1 aa','A','The Punnett square for Aa × Aa produces 1/4 AA, 2/4 Aa, and 1/4 aa, giving a 1:2:1 genotypic ratio.'),
('AP Biology','easy','genetics','Which of the following is an example of complete dominance?','Both alleles are expressed equally in the heterozygote','The heterozygote shows an intermediate phenotype','One allele completely masks the expression of the other allele','Multiple genes affect a single trait','C','Complete dominance occurs when one allele (dominant) completely masks the phenotypic effect of the other allele (recessive) in a heterozygote.'),
('AP Biology','easy','genetics','What is codominance?','One allele is partially dominant over another','Both alleles are fully and simultaneously expressed in the heterozygote','The recessive allele is expressed more strongly','Neither allele is expressed in the heterozygote','B','In codominance, both alleles contribute equally to the phenotype and are both visible — for example, AB blood type where both A and B antigens are present on red blood cells.'),
('AP Biology','easy','genetics','What is the human ABO blood type system an example of?','Complete dominance only','Multiple alleles and codominance','Simple Mendelian dominance','Sex-linked inheritance','B','The ABO system involves three alleles (I^A, I^B, i) where I^A and I^B are codominant with each other and both dominant over i, illustrating both multiple alleles and codominance.'),
('AP Biology','easy','genetics','What is incomplete dominance?','One allele completely suppresses the other','Both alleles are expressed equally','The heterozygote shows an intermediate phenotype between the two homozygotes','The recessive allele is expressed in males only','C','In incomplete dominance, neither allele is fully dominant; the heterozygote shows a blended intermediate phenotype (e.g., red × white flowers produce pink offspring).'),
('AP Biology','easy','genetics','What is the law of independent assortment?','Alleles of the same gene separate during meiosis','Genes on the same chromosome are always inherited together','Alleles of different genes are distributed to gametes independently of one another','Dominant alleles are always expressed','C','Mendel''s law of independent assortment states that genes on different chromosomes are inherited independently; during meiosis, the segregation of one pair of alleles does not affect another pair.'),
('AP Biology','easy','genetics','What is a test cross?','A cross between two homozygous dominant individuals','A cross between an unknown genotype and a homozygous recessive individual to determine the unknown genotype','A cross between two heterozygous individuals','A cross between individuals of different species','B','A test cross uses a homozygous recessive individual to determine whether the organism with the dominant phenotype is homozygous dominant or heterozygous, based on the offspring ratios.'),
('AP Biology','easy','genetics','How many chromosomes do human somatic (body) cells normally contain?','23','46','92','48','B','Human somatic cells are diploid (2n) and contain 46 chromosomes arranged in 23 homologous pairs.'),
('AP Biology','easy','genetics','What term describes the failure of chromosomes or chromatids to separate during meiosis?','Crossing over','Mutation','Nondisjunction','Translocation','C','Nondisjunction occurs when chromosomes fail to separate properly during meiosis I or meiosis II, resulting in gametes with abnormal chromosome numbers.'),
('AP Biology','easy','genetics','What genetic condition results from having three copies of chromosome 21?','Turner syndrome','Klinefelter syndrome','Down syndrome','Cri-du-chat syndrome','C','Down syndrome (trisomy 21) results from three copies of chromosome 21, typically due to nondisjunction during meiosis in a parent.'),
('AP Biology','easy','genetics','What is a mutation?','A change in the phenotype without any DNA change','A permanent change in the DNA sequence of a gene','The normal variation in a gene across a population','The exchange of genes between homologous chromosomes','B','A mutation is any heritable change in the DNA sequence, including base substitutions, insertions, or deletions, which may alter gene expression or protein function.'),
('AP Biology','easy','genetics','Which of the following is a sex-linked trait?','ABO blood type','Huntington''s disease','Color blindness','Cystic fibrosis','C','Red-green color blindness is caused by genes on the X chromosome (sex-linked/X-linked); because males have only one X chromosome, they are more frequently affected than females.'),
('AP Biology','easy','genetics','In humans, which sex chromosomes do females have?','XY','YY','XX','XO','C','Human females have two X chromosomes (XX), while males have one X and one Y chromosome (XY).'),
('AP Biology','easy','genetics','What is the term for the physical location of a gene on a chromosome?','Allele','Phenotype','Locus','Codon','C','A locus (plural: loci) is the specific position of a gene or DNA sequence on a chromosome, like an address in the genome.'),
('AP Biology','easy','genetics','What is epistasis?','The interaction of alleles at the same gene locus','The interaction between genes at different loci where one gene affects the expression of another','The blending of traits in heterozygotes','The inheritance of traits from maternal chromosomes only','B','Epistasis occurs when the expression of one gene (epistatic gene) masks or modifies the expression of a gene at a different locus (hypostatic gene).'),
('AP Biology','easy','genetics','What is a Punnett square used for?','To draw the structure of DNA','To predict the probability of different genotypes and phenotypes in offspring','To sequence genes','To visualize chromosome structure','B','A Punnett square is a diagram used to predict the genotypic and phenotypic ratios of offspring from a genetic cross based on parental genotypes.'),
('AP Biology','easy','genetics','Which type of inheritance involves traits controlled by many genes, each contributing a small additive effect?','Mendelian inheritance','Codominant inheritance','Polygenic inheritance','X-linked inheritance','C','Polygenic traits (like height, skin color, intelligence) are controlled by multiple genes at different loci, each contributing an additive effect, resulting in a continuous range of phenotypes.'),
('AP Biology','easy','genetics','What is the difference between the genotype and phenotype of an organism?','Genotype is visible; phenotype is not','Genotype is the genetic makeup; phenotype is the observable expression of that makeup','Genotype changes during life; phenotype is fixed','Phenotype includes only physical appearance; genotype includes behavior','B','The genotype is the organism''s actual genetic composition (allele combinations), while the phenotype is the observable traits that result from the interaction of genotype with the environment.'),
('AP Biology','easy','genetics','What event during meiosis I increases genetic diversity by exchanging segments between homologous chromosomes?','Nondisjunction','Random assortment','Crossing over (recombination)','DNA replication','C','During prophase I of meiosis, homologous chromosomes pair up and exchange segments at chiasmata in a process called crossing over, creating new combinations of alleles on chromosomes.'),
('AP Biology','easy','genetics','What is a carrier in genetics?','An organism that expresses a genetic disease','An organism that is heterozygous for a recessive allele and does not show the trait but can pass it to offspring','A homozygous dominant organism','An organism with a chromosomal deletion','B','A carrier is heterozygous for a recessive allele; they do not show the recessive trait but can pass the recessive allele to their offspring, who may then be affected.'),
('AP Biology','easy','genetics','What is the probability of an offspring being homozygous recessive (aa) from the cross Aa × Aa?','25%','50%','75%','100%','A','From Aa × Aa, the Punnett square shows 1/4 AA, 2/4 Aa, 1/4 aa; thus there is a 25% probability of the homozygous recessive genotype.'),
('AP Biology','easy','genetics','Which of the following describes a dihybrid cross?','A cross involving one pair of contrasting traits','A cross involving two pairs of contrasting traits','A cross between organisms of different species','A cross between two homozygous recessive individuals','B','A dihybrid cross tracks the inheritance of two different traits simultaneously, such as seed color and seed shape in Mendel''s pea experiments.'),
('AP Biology','easy','genetics','What is the expected phenotypic ratio from a dihybrid cross between two individuals heterozygous for both traits (AaBb × AaBb)?','3:1','9:3:3:1','1:1:1:1','1:2:1','B','Applying the law of independent assortment to a dihybrid cross of AaBb × AaBb gives a 9:3:3:1 phenotypic ratio (9 A_B_ : 3 A_bb : 3 aaB_ : 1 aabb).'),
('AP Biology','easy','genetics','What is genomic imprinting?','A technique for sequencing the genome','A process where gene expression depends on which parent contributed the allele','A form of mutation caused by the environment','The duplication of an entire genome','B','Genomic imprinting is an epigenetic process where certain genes are expressed in a parent-of-origin manner; only the maternal or paternal copy is expressed, not both.'),
('AP Biology','easy','genetics','What is the term for the situation where an organism has more than two complete sets of chromosomes?','Aneuploidy','Haploidy','Polyploidy','Diploidy','C','Polyploidy refers to having more than two complete chromosome sets (e.g., tetraploidy = 4 sets); it is common in plants and contributes to speciation.'),
('AP Biology','easy','genetics','What does homozygous dominant look like using letters?','Aa','aa','AA','aA','C','Homozygous dominant means both alleles are the dominant form, written as two uppercase letters (e.g., AA).'),
('AP Biology','easy','genetics','Which Mendelian principle states that gametes carry only one allele per gene?','Law of independent assortment','Law of dominance','Law of segregation','Law of recombination','C','The law of segregation (Mendel''s first law) states that during gamete formation, the two alleles for each gene separate so each gamete contains only one allele.'),
('AP Biology','easy','genetics','What is the term for genes located on the same chromosome?','Independent genes','Linked genes','Codominant genes','Epistatic genes','B','Linked genes are located on the same chromosome and tend to be inherited together unless separated by crossing over during meiosis.'),
('AP Biology','easy','genetics','What is a chromosome?','A single gene on a strand of RNA','A long DNA molecule with associated proteins that carries genetic information','A type of ribosome involved in translation','A protein that regulates transcription','B','A chromosome is a tightly coiled structure consisting of a long DNA molecule complexed with histone proteins, carrying many genes organized in a linear sequence.'),
('AP Biology','easy','genetics','What is the role of DNA polymerase in replication?','Unwind the double helix','Add new nucleotides to the growing DNA strand','Cut DNA at specific sequences','Translate DNA into protein','B','DNA polymerase adds complementary nucleotides to the 3'' end of a new DNA strand using the existing strand as a template, always synthesizing in the 5'' to 3'' direction.'),
('AP Biology','easy','genetics','What is a point mutation?','A change affecting an entire chromosome','A change in a single nucleotide base pair in the DNA sequence','A large deletion of a chromosome segment','A mutation caused only by radiation','B','A point mutation is a change in a single nucleotide, which can be a substitution (replacing one base with another), an insertion, or a deletion.'),
('AP Biology','easy','genetics','Which of the following conditions is caused by a dominant allele?','Cystic fibrosis','Tay-Sachs disease','Phenylketonuria','Huntington''s disease','D','Huntington''s disease is caused by a single dominant allele; a person needs only one copy to develop the disease, which is why it can be passed from one affected parent.'),
('AP Biology','easy','genetics','What is the term for the full set of chromosomes in an organism displayed in a standardized format?','Genome','Karyotype','Genotype','Proteome','B','A karyotype is a photograph or diagram of an organism''s chromosomes arranged in homologous pairs by size and shape, used to detect chromosomal abnormalities.'),
('AP Biology','easy','genetics','What is pleiotropy?','When one gene affects multiple traits','When multiple genes affect one trait','When the environment affects gene expression','When two genes are on the same chromosome','A','Pleiotropy occurs when a single gene influences multiple different phenotypic traits; for example, the gene for sickle cell hemoglobin affects red blood cell shape, oxygen carrying capacity, and resistance to malaria.'),
('AP Biology','easy','genetics','If a woman is a carrier for an X-linked recessive trait, what is the probability that her son will be affected?','0%','25%','50%','100%','C','A carrier mother is X^N X^n; she passes either X^N or X^n to sons. Sons who receive X^n (probability 1/2 = 50%) will be affected since males have only one X chromosome.'),
('AP Biology','easy','genetics','What is the source of genetic variation produced by meiosis?','Mitosis of germ cells','DNA replication errors only','Independent assortment, crossing over, and random fertilization','Environmental factors alone','C','Meiosis generates genetic diversity through independent assortment of chromosomes, crossing over between homologs during prophase I, and the random fusion of gametes at fertilization.'),
('AP Biology','easy','genetics','What is an autosome?','A sex chromosome','Any chromosome that is not a sex chromosome','A chromosome found only in plants','A single-stranded DNA molecule','B','Autosomes are chromosomes other than sex chromosomes; humans have 22 pairs of autosomes and one pair of sex chromosomes (X and Y).'),
('AP Biology','easy','genetics','What type of mutation adds one or more nucleotides to a DNA sequence?','Substitution','Deletion','Insertion','Inversion','C','An insertion mutation adds one or more extra nucleotides into the DNA sequence; if not a multiple of three, it causes a frameshift that alters all downstream codons.'),
('AP Biology','easy','genetics','What is the term for when two genes are so far apart on the same chromosome that they assort independently?','Linkage','Recombination','Independent assortment mimicry','Chromosomal crossing over','C','Genes far apart on the same chromosome experience so many crossovers between them that they effectively assort independently, mimicking genes on different chromosomes, though they are technically linked.'),
('AP Biology','easy','genetics','In genetics, what does the term "wild type" refer to?','A mutant phenotype seen in the wild','The most common or standard phenotype in a natural population','A phenotype only seen in laboratory settings','A recessive phenotype','B','Wild type refers to the normal or typical form of a gene or phenotype as found in a natural (wild) population, serving as the reference against which mutations are compared.')
,
-- ============================================================
-- GENETICS — MEDIUM (49 questions)
-- ============================================================
('AP Biology','medium','genetics','In a cross between a homozygous dominant (RR) and a homozygous recessive (rr) individual, what are the expected genotype and phenotype of all offspring?','All rr, all recessive phenotype','All Rr, all dominant phenotype','Half Rr and half rr','All RR, all dominant phenotype','B','Every offspring of RR × rr receives one R allele from the dominant parent and one r from the recessive parent, producing all Rr heterozygotes expressing the dominant phenotype.'),
('AP Biology','medium','genetics','A woman with normal color vision whose father was color blind marries a man with normal color vision. What is the probability their son will be color blind?','0%','25%','50%','100%','C','The woman must be a carrier (X^N X^n) since her father was color blind. Each son has a 50% chance of inheriting X^n and, having no second X to mask it, will be color blind.'),
('AP Biology','medium','genetics','Two plants heterozygous for flower color (Rr, where red R is incompletely dominant over white r, and Rr = pink) are crossed. What are the expected phenotypic ratios?','All pink','1 red : 2 pink : 1 white','3 red : 1 white','1 red : 1 white','B','With incomplete dominance, Rr × Rr gives 1 RR (red) : 2 Rr (pink) : 1 rr (white) — a 1:2:1 phenotypic ratio that mirrors the genotypic ratio.'),
('AP Biology','medium','genetics','A test cross of an organism showing the dominant phenotype yields offspring in a 1:1 ratio of dominant to recessive phenotype. What was the genotype of the organism being tested?','Homozygous dominant (AA)','Heterozygous (Aa)','Homozygous recessive (aa)','Cannot be determined','B','A 1:1 offspring ratio from a test cross (× aa) means the tested parent contributed A and a alleles equally, confirming it was heterozygous (Aa).'),
('AP Biology','medium','genetics','Cystic fibrosis is caused by a recessive allele (c). Two carriers (Cc × Cc) have four children. What is the probability that exactly three of the four children will be unaffected?','6/256','27/64','108/256','4/256','C','Each child has a 3/4 probability of being unaffected (CC or Cc). The probability of exactly 3 out of 4 = C(4,3) × (3/4)^3 × (1/4)^1 = 4 × 27/64 × 1/4 = 108/256 ≈ 0.422.'),
('AP Biology','medium','genetics','In a dihybrid cross AaBb × AaBb, what fraction of offspring are expected to be homozygous recessive for both traits (aabb)?','1/4','1/8','1/16','1/9','C','The probability of aa = 1/4 and bb = 1/4; by the product rule (independent assortment), P(aabb) = 1/4 × 1/4 = 1/16.'),
('AP Biology','medium','genetics','A gene on the X chromosome (X-linked recessive) causes hemophilia. A woman carrier (X^H X^h) has children with an unaffected man (X^H Y). What fraction of their daughters will be carriers?','1/4','1/2','3/4','All daughters','B','Daughters receive X^H from their father. They receive X^H or X^h from their carrier mother. So 1/2 of daughters will be X^H X^H (normal) and 1/2 will be X^H X^h (carriers).'),
('AP Biology','medium','genetics','A man has type A blood (I^A i) and a woman has type B blood (I^B i). What blood types are possible in their children?','Only A and B','A, B, AB, and O','Only AB','A and O only','B','From I^A i × I^B i, possible offspring genotypes are I^A I^B (AB), I^A i (A), I^B i (B), and ii (O) — all four blood types are possible.'),
('AP Biology','medium','genetics','Two genes are located 20 centimorgans apart on the same chromosome. In a dihybrid cross of double heterozygotes (AB/ab × ab/ab), what percentage of recombinant offspring would you expect?','5%','10%','20%','40%','C','Map distance in centimorgans corresponds to the recombination frequency; 20 centimorgans apart means 20% recombinant offspring (equal proportions of Ab and aB gametes).'),
('AP Biology','medium','genetics','A cross is performed in Drosophila involving body color (gray B dominant, black b) and wing size (normal V dominant, vestigial v). The genes are linked. In a BV/bv × bv/bv cross, 41% gray-normal, 41% black-vestigial, 9% gray-vestigial, and 9% black-normal offspring are obtained. What is the recombination frequency?','9%','18%','41%','50%','B','Recombinant classes (gray-vestigial + black-normal) = 9% + 9% = 18%. This represents the recombination frequency between the two linked genes.'),
('AP Biology','medium','genetics','What is the molecular cause of sickle cell anemia?','A deletion of the entire beta-globin gene','A single nucleotide substitution in the beta-globin gene causing a glutamic acid to valine change','Duplication of the alpha-globin gene','Insertion of a transposable element into the beta-globin promoter','B','Sickle cell anemia is caused by a point mutation (GAG → GTG) in codon 6 of the beta-globin gene, replacing glutamic acid with valine, causing hemoglobin to polymerize under low oxygen conditions.'),
('AP Biology','medium','genetics','What is the chi-square test used for in genetics?','To determine the exact genotype of an organism','To determine whether observed offspring ratios differ significantly from expected Mendelian ratios','To sequence the DNA of genes','To calculate the frequency of recombination','B','The chi-square test compares observed vs. expected phenotypic ratios to determine if deviations from Mendelian ratios are due to chance or indicate that the hypothesis is incorrect.'),
('AP Biology','medium','genetics','A couple learns that they are both carriers of PKU (an autosomal recessive disorder). They want 2 children. What is the probability that both children will be affected?','1/4','1/8','1/16','1/2','C','Each child has a 1/4 chance of being affected (aa). By the product rule, P(both affected) = 1/4 × 1/4 = 1/16.'),
('AP Biology','medium','genetics','What is meant by the term "penetrance" in genetics?','The degree to which a gene is expressed in the phenotype','The proportion of individuals with a given genotype who actually show the associated phenotype','The number of genes that affect a single trait','The rate of mutation in a gene','B','Penetrance is the proportion of individuals with a particular genotype who exhibit the expected phenotype; incomplete penetrance means some individuals carry the allele but do not show the phenotype.'),
('AP Biology','medium','genetics','Expressivity refers to which of the following?','Whether or not a genotype is expressed','The degree to which a phenotype is expressed among individuals who show the trait','The number of alleles for a given gene','The rate of gene transcription','B','Expressivity describes the degree or intensity of phenotype expression among individuals who do show the trait; variable expressivity means individuals with the same genotype show different levels of phenotypic expression.'),
('AP Biology','medium','genetics','An individual has the genotype AaBbCc. How many different types of gametes can this individual produce (assuming independent assortment)?','2','4','6','8','D','For each heterozygous gene pair, there are 2 possible alleles per gamete; with 3 independent gene pairs: 2^3 = 8 different gamete types.'),
('AP Biology','medium','genetics','Mendel''s law of independent assortment applies most accurately when genes are:','On the same chromosome close together','Located on non-homologous chromosomes or very far apart on the same chromosome','Affected by imprinting','Sex-linked on the X chromosome','B','Independent assortment works when genes segregate without influencing each other — this is true for genes on different (non-homologous) chromosomes or very far apart on the same chromosome.'),
('AP Biology','medium','genetics','A child is born with Turner syndrome (45, X). During which parental meiotic division is nondisjunction most likely to have occurred?','Paternal meiosis I or maternal meiosis I or II, all resulting in an egg or sperm lacking a sex chromosome','Only during mitosis of early embryo cells','Only during S-phase before meiosis begins','Nondisjunction cannot cause Turner syndrome','A','Turner syndrome (45, X) results from a gamete with no sex chromosome fusing with a normal gamete; this can result from nondisjunction during meiosis I or meiosis II in either parent, producing an egg or sperm with no sex chromosome.'),
('AP Biology','medium','genetics','A frameshift mutation differs from a point substitution mutation because:','A frameshift changes one codon at a time','A frameshift inserts or deletes nucleotides in numbers that are not a multiple of three, altering the reading frame and all downstream codons','A frameshift affects only one amino acid','A frameshift is always silent','B','Inserting or deleting a number of nucleotides not divisible by three shifts the reading frame, changing every codon downstream of the mutation and usually producing a severely altered or truncated protein.'),
('AP Biology','medium','genetics','In Huntington''s disease, a trinucleotide repeat expansion (CAG) occurs in the HTT gene. Longer repeat tracts cause earlier disease onset. What type of mutation is this?','A point mutation','A chromosomal inversion','A trinucleotide repeat expansion (dynamic mutation)','A silent mutation','C','Trinucleotide repeat expansions are a type of dynamic mutation where the repeated sequence can expand during replication; the longer the CAG repeat in HTT, the longer the polyglutamine tract and the more severe the neurodegeneration.'),
('AP Biology','medium','genetics','What is the phenotypic outcome of having one extra X chromosome in a male (XXY)?','Down syndrome','Turner syndrome','Klinefelter syndrome','Patau syndrome','C','Klinefelter syndrome (47, XXY) results from an extra X chromosome in males, causing infertility, reduced testosterone, and some feminization; caused by nondisjunction during meiosis.'),
('AP Biology','medium','genetics','How does the environment affect gene expression? Give a relevant example.','Genes always override the environment completely','Environmental factors can modify gene expression; for example, Himalayan rabbits have temperature-sensitive pigment enzyme expression, with dark fur in cold extremities','Environment determines the phenotype with no genetic component','Genes and environment never interact','B','Gene expression is often sensitive to environmental conditions; in Himalayan rabbits, the pigment enzyme is heat-sensitive and only active in cool extremities, demonstrating how temperature can modulate phenotype from the same genotype.'),
('AP Biology','medium','genetics','A gene has two alleles: T (tall, dominant) and t (short, recessive). If you cross a Tt plant with a tt plant, what percentage of offspring will be tall?','25%','50%','75%','100%','B','The test cross Tt × tt produces 1/2 Tt (tall) and 1/2 tt (short), so 50% of offspring will express the tall phenotype.'),
('AP Biology','medium','genetics','What is the purpose of gel electrophoresis in genetics?','To sequence DNA directly','To separate DNA fragments by size for analysis','To amplify specific DNA sequences','To introduce foreign DNA into cells','B','Gel electrophoresis uses an electric field to separate DNA fragments by size as they migrate through a gel matrix; smaller fragments travel farther, creating a pattern used to identify specific fragments.'),
('AP Biology','medium','genetics','Restriction enzymes are used in genetic research. What is their function?','They replicate DNA','They cut DNA at specific nucleotide sequences','They join DNA fragments together','They translate mRNA into protein','B','Restriction endonucleases recognize and cut specific short DNA sequences (restriction sites), producing defined fragments used in cloning, mapping, and DNA analysis.'),
('AP Biology','medium','genetics','What does PCR (polymerase chain reaction) accomplish?','It separates DNA fragments by size','It amplifies a specific DNA sequence millions of times','It introduces mutations into DNA','It sequences the entire genome at once','B','PCR uses repeated cycles of denaturation, primer annealing, and DNA synthesis to exponentially amplify a targeted DNA sequence, producing millions of copies from a tiny starting sample.'),
('AP Biology','medium','genetics','A Northern blot detects:','DNA sequences','RNA molecules','Proteins','Carbohydrates','B','A Northern blot is a technique that detects specific RNA molecules by separating RNA by size via gel electrophoresis, transferring to a membrane, and probing with a complementary labeled DNA or RNA sequence.'),
('AP Biology','medium','genetics','What is the Hardy-Weinberg equilibrium in relation to genetics?','A model describing how evolution always changes allele frequencies','A mathematical model describing allele frequencies in a non-evolving population where p^2 + 2pq + q^2 = 1','A description of how dominant alleles always increase in frequency','A model that applies only to small populations','B','The Hardy-Weinberg principle states that in a large, random-mating population with no selection, mutation, migration, or genetic drift, allele and genotype frequencies remain constant across generations.'),
('AP Biology','medium','genetics','If the frequency of a recessive allele (q) in a population is 0.3, what is the frequency of the dominant allele (p)?','0.3','0.09','0.7','0.6','C','In the Hardy-Weinberg model, p + q = 1; therefore p = 1 - q = 1 - 0.3 = 0.7.'),
('AP Biology','medium','genetics','Using Hardy-Weinberg equations, if q = 0.2, what is the expected frequency of heterozygotes in the population?','0.04','0.16','0.32','0.64','C','The frequency of heterozygotes = 2pq = 2 × 0.8 × 0.2 = 0.32, where p = 1 - 0.2 = 0.8.'),
('AP Biology','medium','genetics','What is epigenetics?','Changes to the DNA sequence that alter gene expression','Changes in gene expression caused by modifications to DNA or histones (e.g., methylation, acetylation) without altering the underlying DNA sequence','The study of genes expressed only in the epidermis','The process of gene duplication during evolution','B','Epigenetics studies heritable changes in gene expression that do not involve changes to the DNA sequence itself; mechanisms include DNA methylation and histone modification, which alter how accessible chromatin is to transcription machinery.'),
('AP Biology','medium','genetics','A researcher uses CRISPR-Cas9 to knock out a gene in mice. Which statement best describes how this technology works?','It adds a gene to the genome at a random location','Guide RNA directs Cas9 endonuclease to a specific DNA sequence, which it cuts, allowing deletion or replacement of the targeted gene','It methylates the target gene to silence it permanently','It copies the target gene to create multiple additional alleles','B','CRISPR-Cas9 uses a guide RNA complementary to the target DNA sequence to direct the Cas9 nuclease to that location, where it makes a double-strand cut; the cell''s repair machinery can then be used to knock out or edit the gene.'),
('AP Biology','medium','genetics','In genetics, what is penetrance of 80% for a dominant allele mean?','80% of all alleles in the population are dominant','Only 80% of individuals who carry the dominant allele actually show the phenotype','The dominant allele is expressed at 80% of its maximum level','80% of offspring from a cross will be dominant','B','80% penetrance means that of all individuals who possess the dominant allele, only 80% actually express the phenotypic trait; 20% carry the allele but appear phenotypically normal.'),
('AP Biology','medium','genetics','What is the significance of the recombination frequency between two genes for genetic mapping?','Higher recombination frequency means the genes are closer together','Recombination frequency is proportional to the distance between genes; genes farther apart recombine more frequently (up to 50%)','Recombination frequency is constant regardless of gene distance','Only genes on the X chromosome show recombination','B','The frequency of recombinant offspring reflects how often crossing over occurs between two loci; greater distance increases the chance of a crossover, so recombination frequency (up to 50%) is used to estimate genetic map distance in centimorgans.'),
('AP Biology','medium','genetics','What type of chromosomal mutation involves a segment of a chromosome being transferred to a non-homologous chromosome?','Deletion','Inversion','Duplication','Translocation','D','A translocation occurs when a chromosome segment is transferred to a different (non-homologous) chromosome, potentially disrupting genes or creating novel gene fusions (as in the Philadelphia chromosome in CML).'),
('AP Biology','medium','genetics','A segment of a chromosome is removed and reinserted in the reverse orientation. What type of chromosomal mutation is this?','Deletion','Inversion','Duplication','Translocation','B','An inversion occurs when a chromosomal segment is cut out and reinserted in the reverse orientation, potentially affecting gene regulation if the inversion includes a promoter region.'),
('AP Biology','medium','genetics','In genetics, what is meant by the term "locus heterogeneity"?','Multiple alleles at the same locus cause different phenotypes','Mutations at different gene loci can produce the same phenotype','The same locus has different phenotypic effects in different populations','One allele affects multiple loci','B','Locus heterogeneity describes the situation where mutations in different genes (different loci) can result in the same clinical phenotype; for example, multiple genes can cause inherited forms of deafness.'),
('AP Biology','medium','genetics','A geneticist discovers that two traits that should assort independently (per Mendel''s laws) actually show linkage in experimental crosses. What is the most likely explanation?','Both traits are controlled by the same allele','The genes controlling the two traits are located close together on the same chromosome','One of the traits is autosomal and the other is X-linked','The traits violate the law of dominance','B','Linked genes are located on the same chromosome and tend to be inherited together rather than assorting independently; the closer they are, the less likely a crossover will occur between them.'),
('AP Biology','medium','genetics','What is a reciprocal translocation?','When one chromosome donates a segment to another','When two non-homologous chromosomes each exchange a segment with each other','When a chromosome segment is deleted and re-ligated in the same place','When an entire chromosome is duplicated','B','In a reciprocal translocation, two non-homologous chromosomes exchange segments with each other; the chromosomes are rearranged but no genetic material is lost, though gene expression can be disrupted.'),
('AP Biology','medium','genetics','What is the phenotypic consequence of X-inactivation in mammalian females?','Females express twice as much X-linked gene product as males','One X chromosome in each somatic cell is randomly inactivated, resulting in a mosaic of cells expressing either the maternal or paternal X allele','All cells express only the maternal X chromosome','X-inactivation prevents X-linked diseases in females','B','X-inactivation (Lyon hypothesis) randomly silences one X chromosome in each female somatic cell early in development, creating a mosaic organism where some cells express one X allele and other cells express the other — visible in tortoiseshell cats.'),
('AP Biology','medium','genetics','In the genetics of sex determination, what determines male sex in humans?','Presence of two X chromosomes','Absence of a Y chromosome','Presence of the SRY gene on the Y chromosome','Having more than 22 autosomes','C','The SRY (sex-determining region Y) gene on the Y chromosome encodes a transcription factor that directs embryonic gonads to develop as testes; without SRY, the gonads develop as ovaries regardless of chromosomal sex.'),
('AP Biology','medium','genetics','Which of the following describes a missense mutation?','A mutation that changes a codon to a stop codon','A mutation that changes a codon to code for a different amino acid','A mutation that does not change the amino acid encoded','A mutation that deletes an entire gene','B','A missense mutation is a single nucleotide substitution that alters the codon so that a different amino acid is incorporated into the protein, potentially changing its function.'),
('AP Biology','medium','genetics','A silent mutation is best defined as:','A mutation with no effect on the organism','A mutation that changes a nucleotide but does not change the amino acid sequence due to codon degeneracy','A mutation in a non-coding region','A mutation that is recessive and therefore not expressed','B','A silent (synonymous) mutation changes a nucleotide base in a codon but, due to the redundancy of the genetic code (multiple codons for the same amino acid), the same amino acid is incorporated and the protein sequence is unchanged.'),
('AP Biology','medium','genetics','What type of mutation changes an amino acid codon into a stop codon?','Missense mutation','Silent mutation','Nonsense mutation','Frameshift mutation','C','A nonsense mutation substitutes a single nucleotide that converts an amino acid codon into a premature stop codon (UAA, UAG, or UGA), causing premature termination of translation and a truncated protein.'),
('AP Biology','medium','genetics','Which of the following is an example of polygenic inheritance?','ABO blood type','Cystic fibrosis (single gene)','Human skin color','Huntington''s disease','C','Human skin color is a classic example of polygenic inheritance, controlled by multiple genes (at least 6 loci) each with small additive effects, producing a continuous range of phenotypes from very light to very dark.'),
('AP Biology','medium','genetics','A geneticist studying eye color finds that an individual with two copies of a brown allele and no blue alleles has brown eyes, while an individual with one brown and one blue allele also has brown eyes. An individual with two blue alleles has blue eyes. This is an example of:','Codominance','Incomplete dominance','Complete dominance','Epistasis','C','This describes complete dominance: the brown allele completely masks the effect of the blue allele in heterozygotes, and only homozygous blue individuals show blue eye color.')
,
-- ============================================================
-- GENETICS — HARD (48 questions)
-- ============================================================
('AP Biology','hard','genetics','In a population where cystic fibrosis (autosomal recessive) affects 1 in 2500 people, what is the carrier frequency using Hardy-Weinberg equations?','1/50','1/25','2/25 (approximately 8%)','1/2500','C','q^2 = 1/2500, so q = 1/50. Then p = 1 - 1/50 = 49/50. Carrier frequency 2pq = 2 × (49/50) × (1/50) ≈ 2/50 = 1/25, often approximated as ~1/25 or 4%.'),
('AP Biology','hard','genetics','A researcher performs a three-point testcross and obtains the following classes of offspring: parental (most frequent), single crossovers in region I, single crossovers in region II, and double crossovers (least frequent). How is the gene order determined from this data?','The gene with the highest recombination frequency is in the middle','The gene present in parental class is always in the middle','The gene order is determined by comparing double crossover classes to parental classes — the middle gene has its alleles switched relative to parental types in double crossovers','All classes are equally likely regardless of gene order','C','In a three-point cross, double crossovers switch the alleles of the gene in the middle position relative to the parental arrangement; comparing double crossover genotypes to parental genotypes reveals which gene has changed position, identifying the middle gene and thus the gene order.'),
('AP Biology','hard','genetics','A gene has a recombination frequency of exactly 50% with another gene. What can be concluded?','The genes are very close together on the same chromosome','The genes are far apart on the same chromosome or on different chromosomes; 50% recombination mimics independent assortment','The genes are alleles of the same locus','The genes must be on sex chromosomes','B','When two genes are far apart on the same chromosome (or on different chromosomes), the probability of at least one crossover between them approaches 50%; at this point, the genes behave as if they assort independently, and genetic mapping cannot distinguish between being far apart vs. on different chromosomes using recombination data alone.'),
('AP Biology','hard','genetics','A geneticist finds that two genes show only 8% recombination in females but 20% recombination in males. How can this be explained?','Males have more chromosomes than females','Crossing over rates differ between sexes; females generally have more crossing over along chromosomes but its distribution differs, and males may have suppressed recombination in certain regions','Females have fewer genes than males','The genes are X-linked and behave differently in each sex','B','Recombination frequency can differ between sexes (heterogeneity of recombination); in many organisms, including humans, females have globally higher crossing over rates, but local rates vary—specific genomic regions may show higher or lower recombination in one sex vs. the other.'),
('AP Biology','hard','genetics','What would happen to an organism if a deletion mutation removed the promoter region of a gene?','The gene would produce a shorter protein','Transcription of the gene could not be initiated, so no mRNA or protein would be produced','The protein would be produced in larger amounts because regulation is removed','The gene would be moved to a different chromosome','B','The promoter is the DNA sequence where RNA polymerase binds to initiate transcription; removing it prevents transcription from starting, so no mRNA is produced and the gene is effectively silenced.'),
('AP Biology','hard','genetics','Huntington''s disease shows anticipation — the age of onset decreases in successive generations. What molecular mechanism underlies this observation?','A dominant allele accumulates more copies with age','The CAG trinucleotide repeat in the HTT gene tends to expand during meiosis (especially paternal), so successive generations inherit longer repeats that cause earlier, more severe disease','The allele undergoes progressive methylation silencing','Anticipation is due to ascertainment bias, not a molecular change','B','Trinucleotide repeats are unstable during meiosis and tend to expand, especially when transmitted by the father. Longer CAG repeats produce a longer polyglutamine tract in huntingtin protein, causing more severe neurodegeneration with earlier onset — the basis of anticipation.'),
('AP Biology','hard','genetics','In Drosophila, white eye color (w) is X-linked recessive. A white-eyed female is crossed with a wild-type (red-eyed) male. What are the expected eye color phenotypes in female and male offspring?','All females red-eyed, all males white-eyed','All females white-eyed, all males red-eyed','Half of females red-eyed and half white-eyed; all males red-eyed','All offspring red-eyed','A','White-eyed female is X^w X^w. Wild-type male is X^+ Y. Daughters receive X^+ from father and X^w from mother → all X^+ X^w (carriers, red-eyed). Sons receive Y from father and X^w from mother → X^w Y (white-eyed). So all females red-eyed, all males white-eyed.'),
('AP Biology','hard','genetics','A geneticist crosses two true-breeding strains of mice: one with black fur and short tail, another with white fur and long tail. The F1 are all black with long tails. F2 crosses produce 9 black-long : 3 white-long : 3 black-short : 1 white-short. Suddenly they notice 7 white-short mice in 160 offspring rather than the expected ~10. What statistical tool is most appropriate to test whether this deviation is significant?','t-test','ANOVA','Chi-square goodness-of-fit test','Linear regression','C','The chi-square test compares observed to expected counts in discrete categories; it is the appropriate test to determine whether observed deviations from Mendelian ratios (like fewer white-short mice) could occur by chance.'),
('AP Biology','hard','genetics','What is the molecular basis for codominance of I^A and I^B alleles in the ABO blood group system?','I^A produces A antigens that are dominant over B antigens','I^A and I^B encode different glycosyltransferases that each add different sugar residues to the H antigen independently, so both antigens are present in AB individuals','I^A and I^B are expressed from different chromosomes that combine in heterozygotes','Both alleles produce the same protein but in different cells','B','I^A encodes a galactosyltransferase adding N-acetylgalactosamine to the H antigen (creating A antigen), and I^B encodes a galactosyltransferase adding galactose (creating B antigen). Heterozygous individuals express both enzymes independently, displaying both A and B antigens — true codominance at the molecular level.'),
('AP Biology','hard','genetics','A plant geneticist crosses two pure-breeding varieties with purple flowers and discovers all F1 offspring have white flowers. F2 plants show a 9:7 ratio of purple to white. What genetic phenomenon explains this, and how many genes are involved?','One gene with incomplete dominance','Two genes with epistasis (complementary gene interaction): both dominant alleles at both loci are required for purple pigment production','Three genes with additive effects','One gene with pleiotropic effects on flower color','B','A 9:7 ratio in F2 indicates complementary epistasis involving two genes; purple color requires at least one dominant allele at each of two loci (A_B_). If either or both loci are homozygous recessive (aaB_, A_bb, aabb), white results — only A_B_ (9/16) are purple.'),
('AP Biology','hard','genetics','Explain how the phenomenon of position effects supports the conclusion that gene regulation depends not only on the gene sequence but also on its chromosomal location.','Genes always function the same regardless of position; position effects are a myth','When a gene is moved near heterochromatin or a different regulatory element (e.g., by translocation or inversion), its expression level changes, demonstrating that regulatory sequences and chromatin environment affect transcription','Position effects only occur in bacteria, not eukaryotes','Position effects are caused by mutations in the gene''s coding sequence','B','Position effects show that chromosomal context matters: moving a gene near a silencer or heterochromatin (as in position-effect variegation in Drosophila) changes its expression without altering its coding sequence, proving that regulatory environment is a key determinant of gene activity.'),
('AP Biology','hard','genetics','An experimenter uses CRISPR-Cas9 to introduce a double-strand break at a specific locus in a somatic cell. The break is repaired by non-homologous end joining (NHEJ). What is the most likely result?','Perfect restoration of the original sequence','A small insertion or deletion (indel) at the cut site, likely causing a frameshift and gene knockout','Replacement of the gene with a donor template','Translocation of the cut segment to another chromosome','B','NHEJ is an error-prone repair pathway that often introduces small insertions or deletions at the break site; indels in the coding sequence frequently cause frameshifts that disrupt the reading frame and knockout the gene''s function.'),
('AP Biology','hard','genetics','In a pedigree analysis, a trait appears in every generation, affects males and females equally, and affected individuals always have at least one affected parent. What inheritance pattern is most consistent?','Autosomal recessive','X-linked recessive','Autosomal dominant','X-linked dominant','C','Traits appearing in every generation (vertical transmission), affecting both sexes equally, with every affected individual having an affected parent are hallmarks of autosomal dominant inheritance.'),
('AP Biology','hard','genetics','A scientist finds that a gene critical for eye development when mutated can cause missing eyes. However, inserting the mouse version of this gene (Pax6) into a Drosophila leg cell causes an eye to develop on the leg. What does this tell us about Pax6?','The Drosophila and mouse eyes are derived from the same embryonic structure','Pax6 is a master regulatory transcription factor for eye development conserved across evolution; its function is so conserved that it can direct eye development across species','Mouse and Drosophila cells are identical and therefore interchangeable','The experiment demonstrates that leg and eye tissues are the same in Drosophila','B','Pax6 is a master control gene for eye development conserved from invertebrates to vertebrates; the ability of mouse Pax6 to induce eye formation in Drosophila demonstrates deep evolutionary conservation of developmental gene regulatory networks.'),
('AP Biology','hard','genetics','In a population of 10,000 individuals, 400 have an autosomal recessive condition. If the population is in Hardy-Weinberg equilibrium, how many individuals are expected to be heterozygous carriers?','400','3200','4800','2000','B','q^2 = 400/10000 = 0.04, so q = 0.2, p = 0.8. Carriers (2pq) = 2 × 0.8 × 0.2 × 10000 = 3200 individuals.'),
('AP Biology','hard','genetics','A researcher discovers a new organism where meiosis never occurs and reproduction is always asexual by mitosis. What genetic consequence would you predict over many generations compared to a sexually reproducing species?','The asexual species would generate more genetic variation','The asexual species would have less genetic variation because no recombination or independent assortment shuffles alleles — only mutations create new combinations','Both species would have equal genetic variation','The asexual species would evolve faster because of reduced genetic variation','B','Sexual reproduction via meiosis generates genetic variation through crossing over and independent assortment; without it, asexual lineages can only gain diversity through mutation, leading to lower genotypic diversity and reduced adaptability (related to Muller''s ratchet).'),
('AP Biology','hard','genetics','A man with Klinefelter syndrome (47, XXY) has cells that show one Barr body (inactivated X). If a woman has three X chromosomes (47, XXX), how many Barr bodies do her cells show, and what rule predicts this?','0 Barr bodies; the Lyon hypothesis does not apply to sex chromosome aneuploidies','2 Barr bodies; the Lyon hypothesis states that the number of Barr bodies = number of X chromosomes minus one','1 Barr body; all extra X chromosomes are always inactivated in pairs','3 Barr bodies; all X chromosomes are inactivated except those needed for development','B','According to the Lyon hypothesis, all X chromosomes except one are inactivated in somatic cells; the number of Barr bodies = (number of X chromosomes - 1). A 47, XXX female has 3 X chromosomes, so she has 2 Barr bodies.'),
('AP Biology','hard','genetics','What is the expected outcome of a cross between a female Drosophila heterozygous for an autosomal lethal recessive allele (Aa) and a male also Aa? The homozygous dominant (AA) dies before birth.','3 Aa : 1 aa phenotypic ratio','2 Aa : 1 aa (live offspring) because AA are lethal','1 Aa : 1 aa ratio','All offspring are aa','B','From Aa × Aa: expected are 1/4 AA (lethal), 2/4 Aa, 1/4 aa. With AA dying before birth, the surviving offspring are 2 Aa : 1 aa, producing a 2:1 ratio of dominant-phenotype survivors to recessive-phenotype survivors.'),
('AP Biology','hard','genetics','A deletion of a large chromosomal segment is generally more harmful than a single nucleotide mutation. Explain why in terms of gene dosage.','A deletion affects fewer genes than a point mutation','Deleting a chromosomal segment eliminates many genes simultaneously, reducing the gene dosage for all deleted loci; haploinsufficiency for multiple essential genes is likely lethal or severely deleterious','Chromosomal deletions are always repaired before causing harm','Point mutations affect regulatory regions more severely than deletions affect coding sequences','B','Large deletions remove multiple genes, creating haploinsufficiency (only one functional copy) for every gene in the deleted region; when any of those genes requires two copies for normal function, the organism is affected — the cumulative effect of losing many genes makes large deletions typically more harmful than point mutations.'),
('AP Biology','hard','genetics','In genomic imprinting, the Igf2 gene (encoding insulin-like growth factor 2) is expressed only from the paternal chromosome, while H19 is expressed only from the maternal chromosome. A mutation inactivates the maternal copy of Igf2. What will happen to Igf2 expression?','Igf2 expression is eliminated because both copies are needed','Igf2 expression is unaffected because only the paternal copy is normally expressed','Igf2 will be expressed at double the normal level','H19 expression will also be eliminated','B','Because Igf2 is subject to genomic imprinting and only the paternal allele is expressed (the maternal allele is silenced by imprinting), inactivating the maternal copy has no effect on Igf2 expression level; the paternal copy is still expressed normally.'),
('AP Biology','hard','genetics','What would be the consequence of a mutation in the enzyme telomerase in a somatic cell line vs. a germline cell?','No consequence in either; telomerase is not needed for cell division','Somatic cells would undergo progressive telomere shortening leading to replicative senescence; germline cells need telomerase to prevent telomere erosion across generations, so a germline mutation would cause progressive telomere shortening in descendants','Somatic cells would gain immortality; germline cells would lose fertility','Telomerase mutations cause cancer only in germline cells','B','Telomerase adds telomeric repeats to chromosome ends; most somatic cells lack telomerase (causing eventual replicative senescence), while germline cells express it. A germline telomerase mutation would cause heritable telomere shortening across generations, eventually compromising genome stability.'),
('AP Biology','hard','genetics','A scientist conducts a genome-wide association study (GWAS) and finds that a SNP (single nucleotide polymorphism) is significantly associated with increased risk of type 2 diabetes. Does this mean the SNP causes diabetes?','Yes, GWAS identifies causal variants directly','Not necessarily; the SNP may be in linkage disequilibrium with the actual causal variant and may not itself be functional — GWAS identifies associations, not causation','Yes, all significant GWAS hits are causal mutations','No; GWAS can only detect recessive traits','B','GWAS identifies statistical associations between SNPs and traits based on linkage disequilibrium; the associated SNP may be in LD with the true causal variant rather than being causal itself. Follow-up functional studies are needed to establish causation.'),
('AP Biology','hard','genetics','Why are X-linked recessive diseases more common in males than females?','Males have two X chromosomes, doubling their chance of inheriting the allele','Males have only one X chromosome, so one copy of the recessive allele is sufficient to produce the disease phenotype since there is no second allele to mask it','X-linked alleles mutate more frequently in males','Males have more copies of recessive alleles due to hormonal differences','B','Males are hemizygous for X-linked genes; they have only one X chromosome, so a single recessive allele on the X is fully expressed with no corresponding dominant allele on the Y chromosome to mask it — hence, males are affected at the rate of the allele frequency (q), while females are affected only at rate q^2.'),
('AP Biology','hard','genetics','What is the molecular basis of the inheritance of mitochondrial diseases such as Leber''s hereditary optic neuropathy (LHON)?','LHON is caused by nuclear DNA mutations inherited in an autosomal dominant pattern','LHON is caused by mutations in mitochondrial DNA, which is maternally inherited because mitochondria are contributed almost exclusively by the egg cell','LHON is caused by X-linked recessive mutations','LHON results from chromosomal trisomy','B','Mitochondria (and their DNA) are inherited almost exclusively from the mother through the egg cytoplasm; LHON mutations in mitochondrial genes encoding electron transport chain subunits are passed to all of a mother''s children but not through the father.'),
('AP Biology','hard','genetics','A scientist discovers a new gene with a mutation that causes flies to develop four wings instead of two. Subsequent studies show this gene controls the expression of dozens of downstream genes. What type of gene is this most likely?','A structural gene encoding a structural protein','A homeotic (Hox) or master regulatory gene that controls developmental gene expression programs','A pseudogene with no normal function','A mitochondrial gene','B','Master regulatory genes (like Hox genes) encode transcription factors that control large developmental programs; mutations in such genes cause homeotic transformations (like the Antennapedia mutation causing legs to grow in place of antennae, or Ultrabithorax mutations causing extra wings).'),
('AP Biology','hard','genetics','A genetics experiment yields F2 offspring in a 15:1 ratio (15 colored : 1 colorless). What type of gene interaction produces this result, and how many genes are involved?','Two genes with complementary interaction (9:7 ratio)','Two genes with duplicate dominant epistasis: having at least one dominant allele at either or both loci produces color','One gene with pleiotropic effects','Three genes with additive effects','B','A 15:1 ratio results from duplicate dominant epistasis: two genes each capable of producing the same pigment independently. Offspring with at least one dominant allele at either locus (A_B_, A_bb, or aaB_) are colored; only aabb (1/16) are colorless, giving a 15:1 ratio.'),
('AP Biology','hard','genetics','In a cross of AaBbCc × AaBbCc, where A, B, and C each contribute one unit to a quantitative trait (minimum 0, maximum 6), what is the probability of an offspring with a trait value of 6?','1/16','1/32','1/64','1/8','C','Trait value of 6 requires all three dominant alleles in homozygous form: AABBCC. P(AA) = 1/4, P(BB) = 1/4, P(CC) = 1/4. By independent assortment: 1/4 × 1/4 × 1/4 = 1/64.'),
('AP Biology','hard','genetics','What is the difference between a somatic mutation and a germline mutation in terms of biological consequences?','Somatic mutations are more harmful because they affect more cells','Germline mutations are inherited by offspring and can spread through populations; somatic mutations affect only the individual and their cell lineage descendants, cannot be passed to offspring, but can cause cancer','There is no difference; all mutations are equally transmitted','Somatic mutations always cause cancer while germline mutations are always silent','B','A germline mutation occurs in egg or sperm cells and can be transmitted to offspring, potentially spreading through populations or causing heritable disease. Somatic mutations occur in body cells and are passed only to daughter cells of that lineage; they can cause cancer but not heritable disease.'),
('AP Biology','hard','genetics','An organism has a diploid chromosome number of 2n = 46. After meiosis I, what is the chromosome content of each cell?','23 chromosomes, each consisting of 2 chromatids','46 chromosomes, each consisting of 1 chromatid','23 chromosomes, each consisting of 1 chromatid','46 chromosomes, each consisting of 2 chromatids','A','After meiosis I, homologous chromosomes have separated, halving the number from 46 to 23; however, each chromosome still consists of two sister chromatids joined at the centromere, so each cell has 23 chromosomes each made of 2 chromatids.'),
('AP Biology','hard','genetics','A researcher discovers a transposable element that has inserted into the coding sequence of a tumor suppressor gene. What would be the likely consequence for cell growth control?','The tumor suppressor gene would be overexpressed','The transposable element insertion would disrupt the reading frame or splicing of the tumor suppressor gene, potentially inactivating it and removing a check on cell proliferation','The transposable element would activate the oncogene next to it only','The cell would repair the insertion before any harm occurs','B','Transposable element insertions into a gene''s coding sequence disrupt its reading frame or splicing signals, often inactivating the gene; inactivation of a tumor suppressor (like Rb or p53) removes a brake on cell division and can contribute to cancer development.'),
('AP Biology','hard','genetics','Using linked genes, the distance between gene A and gene B is 10 cM and between gene B and gene C is 20 cM. Under what conditions could the distance between A and C be 30 cM?','Always, since 10 + 20 = 30','Only if genes A, B, and C are in the order A-B-C with no interference (coefficient of coincidence = 1) and double crossovers are accounted for','Only if genes are on different chromosomes','Only if crossing over is suppressed','B','If A-B-C are arranged linearly with no crossover interference, the map distance from A to C = 10 + 20 = 30 cM; however, if interference exists (positive interference suppresses double crossovers), the observed A-C distance may be less than 30 cM.'),
('AP Biology','hard','genetics','What is the concept of "synthetic lethality" in genetics, and how is it exploited in cancer therapy?','Two mutations each cause lethality alone, but together are viable','Two mutations are each individually viable but lethal in combination; cancer cells with one mutation are selectively killed by drugs that create the second "mutation," while normal cells with neither mutation survive','Synthetic lethality applies only to viral genetics','Lethal mutations are always dominant','B','Synthetic lethality: cells viable with mutation A or mutation B alone die when both are present. Cancer cells often have mutation A (e.g., BRCA1/2 deficiency); targeting pathway B (e.g., PARP inhibitors) creates the lethal combination specifically in cancer cells while sparing normal cells that retain functional BRCA.'),
('AP Biology','hard','genetics','Why does heterozygosity for a chromosomal inversion often reduce fertility?','Inverted chromosome segments cannot replicate DNA','During meiosis, an inversion heterozygote forms a loop to allow homologs to pair; crossovers within the loop produce recombinant chromosomes with deletions and duplications, making those gametes inviable','Inversions always cause nondisjunction','The inverted chromosome cannot segregate during meiosis II','B','In an inversion heterozygote, homologs must form an inversion loop to achieve synapsis; crossing over within the loop produces recombinant chromosomes with duplications of some segments and deletions of others, creating unbalanced gametes that produce inviable zygotes — reducing fertility.'),
('AP Biology','hard','genetics','A gene is expressed at high levels in liver and low levels in kidney. Both cells have the same DNA sequence. What mechanism most likely explains the tissue-specific difference in expression?','The liver has more copies of the gene due to gene amplification','Different transcription factors and epigenetic states (chromatin accessibility, DNA methylation, histone modifications) in liver vs. kidney cells regulate the same gene differently','The kidney cell has a different mRNA sequence','The liver and kidney cells have different genomes due to somatic recombination','B','Tissue-specific gene expression is controlled by cell-type-specific transcription factors, enhancer-binding proteins, and epigenetic marks (DNA methylation and histone modifications) that determine whether chromatin is accessible and whether transcription is initiated at a given locus — the same DNA sequence is interpreted differently in each cell type.'),
('AP Biology','hard','genetics','In a cross-fertilization experiment, a true-breeding purple-flowered plant (PPQQ) is crossed with a true-breeding white-flowered plant (ppqq). The F1 (PpQq) shows purple flowers. However, in the F2, the ratio is 9 purple : 3 red : 4 white. What type of epistasis is this, and what genotypes produce each phenotype?','Dominant epistasis; Q masks p','Recessive epistasis: ppQQ and ppQq (pp_ = red), PPQQ, PPQq, PpQQ, PpQq (P_Q_ = purple), and qqPP, qqPp, qqpp (qq genotypes = white)','Recessive epistasis: qq masks P_ expression, producing white; P_Q_ = purple; ppQ_ = red; the 9:3:4 ratio shows one gene (q) epistatically suppresses the other','Codominance of P and Q alleles','C','In 9:3:4 recessive epistasis, the homozygous recessive genotype at one locus (qq) suppresses expression of the other locus regardless of its genotype, producing white flowers; P_Q_ = purple (9), ppQ_ = red (3), and all qq genotypes = white (4/16).'),
('AP Biology','hard','genetics','What is the molecular mechanism behind genomic imprinting, and why is it significant that imprints are erased and reset each generation?','Imprints are DNA sequence changes; they are inherited directly without erasure','Imprints are epigenetic marks (primarily DNA methylation) that are erased in primordial germ cells and re-established based on the sex of the individual making the gametes; this reset is essential so that the correct parent-of-origin expression pattern is set for each new generation','Imprints are protein modifications that are inherited through the cytoplasm','Imprinting occurs only once at fertilization and never changes','B','Genomic imprinting involves parent-specific DNA methylation patterns; these marks are erased in primordial germ cells and re-established during gametogenesis according to the sex of the organism, so a gene is always imprinted as maternal or paternal regardless of the grandparental source — ensuring proper dosage compensation of growth-regulating genes.'),
('AP Biology','hard','genetics','A researcher creates a transgenic mouse carrying an extra copy of the IGF1 gene under a strong constitutive promoter. The mice are significantly larger than wild type. A cross between two transgenic mice produces some offspring that are extremely large (3 copies of IGF1) and die shortly after birth. What genetic principle does this demonstrate?','Recessive lethality of IGF1','Gene dosage sensitivity: too much IGF1 signaling (from 3 copies) is lethal, while 2 copies cause overgrowth — demonstrating that gene copy number and expression level are tightly regulated for normal development','IGF1 is a tumor suppressor that becomes oncogenic in excess','Transgenes are unstable and mutate to lethal alleles','B','This demonstrates gene dosage sensitivity: the phenotypic effect of IGF1 scales with copy number. Two copies cause overgrowth; three copies cause lethality, showing that normal development requires tightly regulated gene dosage and that exceeding the tolerable range of expression is lethal.'),
('AP Biology','hard','genetics','In bacteria, conjugation transfers genes from donor to recipient. An Hfr (high frequency recombination) cell transfers genes in a defined order determined by the position of the F factor insertion in the chromosome. Using interrupted mating experiments, genes are found in the order: A enters at 5 min, B at 10 min, C at 20 min, D at 25 min. What is the map distance between genes A and B in minutes, and how does this correspond to physical distance?','1 minute, representing 1 kb','5 minutes; in E. coli, 1 minute of mating corresponds to approximately 100 genes or ~47 kb of DNA, so A-B are ~235 kb apart','5 minutes, representing 5 nucleotides','Minutes of mating have no relationship to chromosomal distance','B','In Hfr mating, entry time is directly proportional to chromosomal distance from the F factor insertion; B enters 5 minutes after A, corresponding to ~5 minutes × ~47 kb/min ≈ 235 kb physical distance — demonstrating how temporal mating maps were used to construct the first bacterial genetic maps.'),
('AP Biology','hard','genetics','A population of island finches shows significant variation in beak size. A researcher finds that heritability of beak size is 0.85 in this population. What does this mean, and what does NOT follow from this high heritability?','85% of individuals have the dominant allele for beak size','85% of the variation in beak size among individuals is attributable to genetic differences among them; it does NOT mean that 85% of beak size is determined by genes or that environmental factors are unimportant overall','Heritability of 0.85 means the trait will never change under natural selection','85% of beak size is due to the environment','B','Heritability (h^2 = 0.85) means 85% of the phenotypic variation in beak size within this population is explained by genetic variation; it does not mean 85% of any individual''s beak size is genetic, and heritability values are population- and environment-specific.'),
('AP Biology','hard','genetics','In a family showing autosomal dominant polycystic kidney disease (ADPKD), not all individuals who inherit the mutation develop cysts at the same age or severity. Some develop severe disease by age 30 while others have mild disease at age 70. What genetic concepts explain this variation?','The mutations are inherited at different frequencies in each person','Variable expressivity and genetic modifiers: individuals with the same PKD1 mutation show different disease severity due to other gene variants (modifiers) and environmental factors affecting cyst development','ADPKD shows incomplete penetrance so some individuals do not express any phenotype','The mutation is not inherited; it arises de novo at different rates','B','Variable expressivity means individuals with the same dominant allele show different phenotypic severity; genetic background (modifier genes), environmental factors, and the random somatic second-hit mutations required for cyst formation all contribute to the variation in age of onset and severity in ADPKD.'),
('AP Biology','hard','genetics','What is uniparental disomy (UPD) and why can it cause disease even when both copies of a chromosome are present?','UPD is when one chromosome is deleted; disease results from haploinsufficiency','UPD occurs when both copies of a chromosome come from the same parent; if the chromosome contains imprinted genes, UPD may cause disease by having two silenced copies or two expressed copies of an imprinted gene rather than one of each','UPD is caused by chromosomal translocations','UPD only affects sex chromosomes','B','In UPD, meiotic nondisjunction followed by trisomic rescue can result in both copies of a chromosome coming from one parent; for chromosomes with imprinted genes, having two maternally or two paternally derived copies disrupts the normal one-expressed, one-silenced dosage, causing syndromes like Prader-Willi or Angelman depending on which parent contributed both copies.'),
('AP Biology','hard','genetics','A geneticist finds a new Drosophila mutation affecting wing development. Test crosses show it is recessive and autosomal. However, in a chromosome balancer stock where crossing over in a specific chromosome region is suppressed, the mutation maps between genes at positions 30 and 50 on chromosome 2. Without the balancer, mapping gives inconsistent results. Why would a balancer chromosome be needed for accurate mapping?','Balancer chromosomes increase the rate of crossing over','Balancer chromosomes carry multiple inversions that suppress crossing over, preventing recombination from masking the true location of the mutation in that region','Balancer chromosomes duplicate the target gene to make it easier to detect','Without balancers, all mutations appear dominant','B','Balancer chromosomes carry multiple overlapping inversions that suppress crossing over in heterozygotes; they prevent recombination between the balancer and the target chromosome, allowing stable maintenance of lethal or recessive mutations and accurate mapping without the loss of marked chromosomes through recombination.')
,
